    pub fn tensor_bmm(
        &mut self,
        lhs: TensorNodeId,
        rhs: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let (out, event) = self.tensor_tape.bmm(lhs, rhs, self.mode())?;
        self.record_tensor_operation(&event);
        Ok(out)
    }

    /// Batch matrix multiply with add: `out = beta * input + alpha * (batch1 @ batch2)`.
    ///
    /// Equivalent to `torch.baddbmm(input, batch1, batch2, beta=1, alpha=1)`.
    /// `batch1`: `[B, n, m]`, `batch2`: `[B, m, p]`, `input`: broadcastable to `[B, n, p]`.
    pub fn tensor_baddbmm(
        &mut self,
        input: TensorNodeId,
        batch1: TensorNodeId,
        batch2: TensorNodeId,
        beta: f64,
        alpha: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let bmm_result = self.tensor_bmm(batch1, batch2)?;
        let out_shape = self.tensor_shape(bmm_result)?;

        // Scale bmm result by alpha
        let alpha_tensor = self.full(out_shape.clone(), alpha, false)?;
        let scaled_bmm = self.tensor_mul(bmm_result, alpha_tensor)?;

        // Scale input by beta and add
        let input_expanded = self.tensor_expand(input, out_shape.clone())?;
        let beta_tensor = self.full(out_shape, beta, false)?;
        let scaled_input = self.tensor_mul(input_expanded, beta_tensor)?;

        self.tensor_add(scaled_input, scaled_bmm)
    }

    /// Batch matrix multiply reduced to 2D with add: `out = beta * M + alpha * sum_b(batch1[b] @ batch2[b])`.
    ///
    /// Equivalent to `torch.addbmm(M, batch1, batch2, beta=1, alpha=1)`.
    /// Sums the batch matrix products and adds to `M`.
    pub fn tensor_addbmm(
        &mut self,
        input: TensorNodeId,
        batch1: TensorNodeId,
        batch2: TensorNodeId,
        beta: f64,
        alpha: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let bmm_result = self.tensor_bmm(batch1, batch2)?;
        // Sum over batch dimension (dim 0)
        let summed = self.tensor_sum_dim(bmm_result, 0)?;
        let out_shape = self.tensor_shape(summed)?;

        let alpha_tensor = self.full(out_shape.clone(), alpha, false)?;
        let scaled = self.tensor_mul(summed, alpha_tensor)?;

        let input_expanded = self.tensor_expand(input, out_shape.clone())?;
        let beta_tensor = self.full(out_shape, beta, false)?;
        let scaled_input = self.tensor_mul(input_expanded, beta_tensor)?;

        self.tensor_add(scaled_input, scaled)
    }

    /// Scaled dot-product attention (PyTorch 2.0+).
    ///
    /// Equivalent to `torch.nn.functional.scaled_dot_product_attention(query, key, value, attn_mask, dropout_p, is_causal)`.
    ///
    /// Computes: `softmax(Q @ K^T / sqrt(d_k) + mask) @ V`
    ///
    /// `query`: `[*, L, E]`, `key`: `[*, S, E]`, `value`: `[*, S, Ev]`.
    /// Returns: `[*, L, Ev]`.
    pub fn scaled_dot_product_attention(
        &mut self,
        query: TensorNodeId,
        key: TensorNodeId,
        value: TensorNodeId,
        attn_mask: Option<TensorNodeId>,
        dropout_p: f64,
        is_causal: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        if is_causal && attn_mask.is_some() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "scaled_dot_product_attention: attn_mask cannot be combined with is_causal",
                },
            )));
        }
        let q_shape = self.tensor_shape(query)?;
        let k_shape = self.tensor_shape(key)?;

        if q_shape.len() < 2 || k_shape.len() < 2 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "scaled_dot_product_attention: Q/K must be at least 2-D",
                },
            )));
        }
        if !(0.0..=1.0).contains(&dropout_p) {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "scaled_dot_product_attention: dropout_p must be in [0, 1]",
                },
            )));
        }

        let d_k = q_shape.last().copied().ok_or(AutogradError::Dispatch(
            ft_dispatch::DispatchError::Key(ft_dispatch::DispatchKeyError::IncompatibleSet {
                reason: "scaled_dot_product_attention: missing head dimension",
            }),
        ))?;
        if d_k == 0 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "scaled_dot_product_attention: head dimension must be non-zero",
                },
            )));
        }
        let scale = 1.0 / (d_k as f64).sqrt();

        // Q @ K^T — use bmm for 3D batched inputs, matmul for 2D
        let ndim = k_shape.len();
        let key_t = self.tensor_transpose(key, ndim - 2, ndim - 1)?;
        let attn_weights = if ndim >= 3 {
            self.tensor_bmm(query, key_t)?
        } else {
            self.tensor_matmul(query, key_t)?
        };

        // Scale
        let aw_shape = self.tensor_shape(attn_weights)?;
        let softmax_dim = aw_shape.len() - 1;
        let scale_tensor = self.full(aw_shape.clone(), scale, false)?;
        let scaled = self.tensor_mul(attn_weights, scale_tensor)?;

        // Apply causal mask if requested
        let masked = if is_causal {
            let l = aw_shape[aw_shape.len() - 2];
            let s = aw_shape[aw_shape.len() - 1];
            if l == 0 || s == 0 {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "scaled_dot_product_attention: sequence length must be non-zero",
                    },
                )));
            }
            let total = Self::checked_shape_numel(
                &aw_shape,
                "scaled_dot_product_attention: attention shape volume overflow",
            )?;
            let Some(batch_area) = l.checked_mul(s) else {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "scaled_dot_product_attention: attention shape volume overflow",
                    },
                )));
            };
            let batch_count = total / batch_area;
            let mut mask_data = Vec::with_capacity(total);
            for _ in 0..batch_count {
                for i in 0..l {
                    for j in 0..s {
                        if j > i {
                            mask_data.push(f64::NEG_INFINITY);
                        } else {
                            mask_data.push(0.0);
                        }
                    }
                }
            }
            let causal_mask = self.tensor_variable(mask_data, aw_shape, false)?;
            self.tensor_add(scaled, causal_mask)?
        } else if let Some(mask) = attn_mask {
            self.tensor_add(scaled, mask)?
        } else {
            scaled
        };

        // Softmax along last dim
        let softmaxed = self.tensor_softmax(masked, softmax_dim)?;

        // Apply dropout
        let dropped = if dropout_p > 0.0 {
            self.functional_dropout(softmaxed, dropout_p, true)?
        } else {
            softmaxed
        };

        // attn_weights @ V
        if ndim >= 3 {
            self.tensor_bmm(dropped, value)
        } else {
            self.tensor_matmul(dropped, value)
        }
    }

    /// Tensor contraction over specified dimensions (generalised matrix multiply).
    ///
    /// `dims` is the number of trailing dimensions of `a` to contract with
    /// the leading dimensions of `b`.
    /// Equivalent to PyTorch's `torch.tensordot(a, b, dims=N)`.
    pub fn tensor_tensordot(
        &mut self,
        a: TensorNodeId,
        b: TensorNodeId,
        dims: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        let a_shape = self.tensor_shape(a)?;
        let b_shape = self.tensor_shape(b)?;
        let a_ndim = a_shape.len();
        let b_ndim = b_shape.len();

        if dims > a_ndim || dims > b_ndim {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::InvalidDimension {
                    dim: dims,
                    ndim: a_ndim.min(b_ndim),
                },
            )));
        }

        // Check that contracted dimensions match
        for i in 0..dims {
            if a_shape[a_ndim - dims + i] != b_shape[i] {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                    ft_kernel_cpu::KernelError::ShapeMismatch {
                        lhs: a_shape.clone(),
                        rhs: b_shape.clone(),
                    },
                )));
            }
        }

        // Special case: dims=0 is outer product-like (no contraction)
        if dims == 0 {
            // Reshape a to [..., 1] and b to [1, ...], then matmul
            let a_total =
                Self::checked_shape_numel(&a_shape, "tensordot: lhs shape volume overflow")?;
            let b_total =
                Self::checked_shape_numel(&b_shape, "tensordot: rhs shape volume overflow")?;
            let a_flat = self.tensor_reshape(a, vec![a_total, 1])?;
            let b_flat = self.tensor_reshape(b, vec![1, b_total])?;
            let result = self.tensor_matmul(a_flat, b_flat)?;
            let mut out_shape = a_shape;
            out_shape.extend_from_slice(&b_shape);
            return self.tensor_reshape(result, out_shape);
        }

        // Reshape a: [free_a..., contract...] -> [prod(free_a), prod(contract)]
        let free_a = Self::checked_shape_numel(
            &a_shape[..a_ndim - dims],
            "tensordot: free lhs shape volume overflow",
        )?;
        let contract = Self::checked_shape_numel(
            &a_shape[a_ndim - dims..],
            "tensordot: contract shape volume overflow",
        )?;
        let a_2d = self.tensor_reshape(a, vec![free_a, contract])?;

        // Reshape b: [contract..., free_b...] -> [prod(contract), prod(free_b)]
        let free_b = Self::checked_shape_numel(
            &b_shape[dims..],
            "tensordot: free rhs shape volume overflow",
        )?;
        let b_2d = self.tensor_reshape(b, vec![contract, free_b])?;

        // Matmul: [free_a, contract] @ [contract, free_b] -> [free_a, free_b]
        let result = self.tensor_matmul(a_2d, b_2d)?;

        // Reshape back to [...free_a_dims, ...free_b_dims]
        let mut out_shape: Vec<usize> = a_shape[..a_ndim - dims].to_vec();
        out_shape.extend_from_slice(&b_shape[dims..]);
        if out_shape.is_empty() {
            out_shape.push(1);
        }
        self.tensor_reshape(result, out_shape)
    }

    /// Kronecker product of two tensors.
    ///
    /// If the inputs have different ranks, the lower-rank input is left-padded
    /// with singleton dimensions before multiplying each aligned dimension.
    pub fn tensor_kron(
        &mut self,
        a: TensorNodeId,
        b: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let a_shape = self.tensor_shape(a)?;
        let b_shape = self.tensor_shape(b)?;

        if a_shape.len() == 1 && b_shape.len() == 1 {
            let outer = self.tensor_outer(a, b)?;
            let total = Self::checked_mul(a_shape[0], b_shape[0], "kron: output shape overflow")?;
            return self.tensor_reshape(outer, vec![total]);
        }

        let rank = a_shape.len().max(b_shape.len());
        let mut a_aligned = vec![1usize; rank - a_shape.len()];
        a_aligned.extend_from_slice(&a_shape);
        let mut b_aligned = vec![1usize; rank - b_shape.len()];
        b_aligned.extend_from_slice(&b_shape);

        let mut out_shape = Vec::with_capacity(rank);
        for (&a_dim, &b_dim) in a_aligned.iter().zip(&b_aligned) {
            out_shape.push(Self::checked_mul(
                a_dim,
                b_dim,
                "kron: output shape overflow",
            )?);
        }
        let total = Self::checked_shape_numel(&out_shape, "kron: output shape volume overflow")?;

        if self.tensor_tape.tensor_requires_grad(a)? || self.tensor_tape.tensor_requires_grad(b)? {
            let mut a_kron_shape = Vec::with_capacity(rank * 2);
            let mut b_kron_shape = Vec::with_capacity(rank * 2);
            let mut interleaved_shape = Vec::with_capacity(rank * 2);
            for (&a_dim, &b_dim) in a_aligned.iter().zip(&b_aligned) {
                a_kron_shape.push(a_dim);
                a_kron_shape.push(1);
                b_kron_shape.push(1);
                b_kron_shape.push(b_dim);
                interleaved_shape.push(a_dim);
                interleaved_shape.push(b_dim);
            }

            let a_view = self.tensor_reshape(a, a_kron_shape)?;
            let b_view = self.tensor_reshape(b, b_kron_shape)?;
            let a_expanded = self.tensor_expand(a_view, interleaved_shape.clone())?;
            let b_expanded = self.tensor_expand(b_view, interleaved_shape)?;
            let product = self.tensor_mul(a_expanded, b_expanded)?;
            return self.tensor_reshape(product, out_shape);
        }

        let a_vals = self.tensor_values(a)?;
        let b_vals = self.tensor_values(b)?;
        if total == 0 {
            return self.tensor_variable(Vec::new(), out_shape, false);
        }

        // Precompute contiguous strides for the aligned shapes ONCE before the
        // hot loop (frankentorch-ys3y). The earlier implementation allocated a
        // fresh `Vec<usize>` of length `rank` on every iteration of the
        // doubly-nested loop via a `decode_coords` closure, which made a 2D x
        // 2D kron of N x N inputs do O(N^4) Vec allocations. With strides in
        // hand we can decompose `a_linear` and `b_linear` into per-dim
        // coordinates with simple integer division and recombine into
        // `out_linear` without any per-iteration heap activity.
        //
        // All bounds below are mathematically guaranteed to fit in `usize`:
        // for any valid (a_linear, b_linear), each dim's `out_coord` is in
        // `[0, out_shape[dim])`, and the running `out_linear` stays in
        // `[0, total)` (already validated to fit in `usize` above). We keep
        // checked arithmetic anyway to match the surrounding hardening style
        // and to fail closed on any future invariant violation.
        let a_strides = contiguous_strides(&a_aligned);
        let b_strides = contiguous_strides(&b_aligned);

        let mut result = vec![0.0f64; total];
        for (a_linear, &a_val) in a_vals.iter().enumerate() {
            for (b_linear, &b_val) in b_vals.iter().enumerate() {
                let mut out_linear = 0usize;
                for dim in 0..rank {
                    // contiguous_strides guarantees stride >= 1 for every dim
                    // when the shape is non-empty, and we already short-
                    // circuited when `total == 0`.
                    let a_coord = (a_linear / a_strides[dim]) % a_aligned[dim];
                    let b_coord = (b_linear / b_strides[dim]) % b_aligned[dim];
                    let scaled_a = Self::checked_mul(
                        a_coord,
                        b_aligned[dim],
                        "kron: output coordinate overflow",
                    )?;
                    let out_coord =
                        Self::checked_add(scaled_a, b_coord, "kron: output coordinate overflow")?;
                    out_linear = Self::checked_add(
                        Self::checked_mul(
                            out_linear,
                            out_shape[dim],
                            "kron: output index overflow",
                        )?,
                        out_coord,
                        "kron: output index overflow",
                    )?;
                }
                result[out_linear] = a_val * b_val;
            }
        }

        self.tensor_variable(result, out_shape, false)
    }

    /// Einstein summation.
    ///
    /// Supports 1- and 2-operand equations via compact index notation.
    /// Decomposes into permute/reshape/matmul/sum operations for backward compatibility.
    ///
    /// Examples:
    /// - `"ij,jk->ik"` — matrix multiply
    /// - `"ii->"` — trace
    /// - `"ij->ji"` — transpose
    /// - `"i,j->ij"` — outer product
    /// - `"i,i->"` — dot product
    /// - `"bij,bjk->bik"` — batch matmul
    pub fn tensor_einsum(
        &mut self,
        equation: &str,
        tensors: &[TensorNodeId],
    ) -> Result<TensorNodeId, AutogradError> {
        let make_err = |reason: &'static str| {
            AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet { reason },
            ))
        };

        // Parse equation: "subscripts -> output" or just "subscripts" (implicit output)
        let (input_part, output_part) = if let Some(pos) = equation.find("->") {
            (&equation[..pos], Some(&equation[pos + 2..]))
        } else {
            (equation, None)
        };

        let input_subs: Vec<&str> = input_part.split(',').collect();
        if input_subs.len() != tensors.len() {
            return Err(make_err(
                "einsum: number of subscripts must match number of tensors",
            ));
        }

        // Validate characters: only lowercase ASCII letters
        for ch in equation.chars() {
            if ch != ',' && ch != '-' && ch != '>' && ch != ' ' && !ch.is_ascii_lowercase() {
                return Err(make_err(
                    "einsum: only lowercase ASCII letters allowed in subscripts",
                ));
            }
        }

        // Parse subscripts into index lists
        let input_indices: Vec<Vec<char>> = input_subs
            .iter()
            .map(|s| s.chars().filter(|c| c.is_ascii_lowercase()).collect())
            .collect();

        // Validate shapes match subscripts
        for (i, indices) in input_indices.iter().enumerate() {
            let shape = self.tensor_shape(tensors[i])?;
            if shape.len() != indices.len() {
                return Err(make_err("einsum: subscript length must match tensor ndim"));
            }
        }

        // Build dimension size map
        let mut dim_sizes: std::collections::HashMap<char, usize> =
            std::collections::HashMap::new();
        for (i, indices) in input_indices.iter().enumerate() {
            let shape = self.tensor_shape(tensors[i])?;
            for (d, &idx) in indices.iter().enumerate() {
                if let Some(&existing) = dim_sizes.get(&idx) {
                    if existing != shape[d] {
                        return Err(make_err(
                            "einsum: dimension size mismatch for repeated index",
                        ));
                    }
                } else {
                    dim_sizes.insert(idx, shape[d]);
                }
            }
        }

        // Determine output indices
        let output_indices: Vec<char> = if let Some(out) = output_part {
            out.chars().filter(|c| c.is_ascii_lowercase()).collect()
        } else {
            // Implicit: sorted unique indices that appear exactly once across all inputs
            let mut counts: std::collections::HashMap<char, usize> =
                std::collections::HashMap::new();
            for indices in &input_indices {
                for &ch in indices {
                    *counts.entry(ch).or_insert(0) += 1;
                }
            }
            let mut out: Vec<char> = counts
                .into_iter()
                .filter(|(_, count)| *count == 1)
                .map(|(ch, _)| ch)
                .collect();
            out.sort();
            out
        };

        // Handle based on number of operands
        match tensors.len() {
            1 => self.einsum_unary(&input_indices[0], &output_indices, tensors[0], &dim_sizes),
            2 => self.einsum_binary(
                &input_indices[0],
                &input_indices[1],
                &output_indices,
                tensors[0],
                tensors[1],
                &dim_sizes,
            ),
            _ => {
                // Multi-operand: pairwise reduction left-to-right
                // Determine which indices to contract at each step
                let mut current = tensors[0];
                let mut current_indices = input_indices[0].clone();
                for i in 1..tensors.len() {
                    let rhs_indices = &input_indices[i];
                    // For intermediate steps, keep all indices needed downstream
                    let is_last = i == tensors.len() - 1;
                    let intermediate_out: Vec<char> = if is_last {
                        output_indices.clone()
                    } else {
                        // Keep indices that appear in remaining inputs or final output
                        let mut needed: std::collections::HashSet<char> =
                            output_indices.iter().copied().collect();
                        for idx_set in &input_indices[(i + 1)..] {
                            for &ch in idx_set {
                                needed.insert(ch);
                            }
                        }
                        let mut out: Vec<char> = current_indices
                            .iter()
                            .chain(rhs_indices.iter())
                            .copied()
                            .filter(|ch| needed.contains(ch))
                            .collect();
                        // Deduplicate while preserving order
                        let mut seen = std::collections::HashSet::new();
                        out.retain(|ch| seen.insert(*ch));
                        out
                    };
                    current = self.einsum_binary(
                        &current_indices,
                        rhs_indices,
                        &intermediate_out,
                        current,
                        tensors[i],
                        &dim_sizes,
                    )?;
                    current_indices = intermediate_out;
                }
                Ok(current)
            }
        }
    }

    fn einsum_unary(
        &mut self,
        input_idx: &[char],
        output_idx: &[char],
        tensor: TensorNodeId,
        _dim_sizes: &std::collections::HashMap<char, usize>,
    ) -> Result<TensorNodeId, AutogradError> {
        let make_err = |reason: &'static str| {
            AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet { reason },
            ))
        };

        // Check for trace pattern: repeated index in input
        let mut repeated: Vec<char> = Vec::new();
        {
            let mut seen = std::collections::HashSet::new();
            for &ch in input_idx {
                if !seen.insert(ch) && !repeated.contains(&ch) {
                    repeated.push(ch);
                }
            }
        }

        if !repeated.is_empty() {
            // Trace-like: extract diagonal(s) then sum/permute
            // For simplicity, handle the common case: "ii->" (trace) and "ii->i" (diagonal)
            if input_idx.len() == 2 && repeated.len() == 1 {
                let shape = self.tensor_shape(tensor)?;
                if shape[0] != shape[1] {
                    return Err(make_err("einsum: trace requires square matrix"));
                }
                if output_idx.is_empty() {
                    // Trace: sum of diagonal
                    return self.tensor_trace(tensor);
                } else if output_idx.len() == 1 && output_idx[0] == repeated[0] {
                    // Diagonal extraction. Delegate to tensor_diagonal
                    // so the autograd path goes through the
                    // diag-scatter backward (frankentorch-sirh).
                    // Previously this body extracted values + rebuilt
                    // a non-grad leaf — silently severing autograd
                    // for the einsum 'ii->i' pattern.
                    return self.tensor_diagonal(tensor, 0);
                }
            }
            return Err(make_err(
                "einsum: unsupported repeated-index pattern for single operand",
            ));
        }

        // No repeated indices: transpose + sum over contracted dims
        // First, figure out which input dims map to which output dims
        let contract_dims: Vec<usize> = input_idx
            .iter()
            .enumerate()
            .filter(|(_, ch)| !output_idx.contains(ch))
            .map(|(i, _)| i)
            .collect();

        let mut current = tensor;

        if output_idx.is_empty() && contract_dims.len() == input_idx.len() {
            // Sum all elements
            let shape = self.tensor_shape(current)?;
            let total = Self::checked_shape_numel(&shape, "einsum: input shape volume overflow")?;
            let flat = self.tensor_reshape(current, vec![total])?;
            return self.tensor_sum_dim(flat, 0);
        }

        // Permute to bring output indices first, then contracted dims
        let mut perm: Vec<usize> = Vec::with_capacity(input_idx.len());
        for &out_ch in output_idx {
            let pos = input_idx
                .iter()
                .position(|&ch| ch == out_ch)
                .ok_or_else(|| make_err("einsum: output index not found in input"))?;
            perm.push(pos);
        }
        for &cd in &contract_dims {
            perm.push(cd);
        }

        if perm.len() == input_idx.len() {
            // Check if permutation is identity
            let is_identity = perm.iter().enumerate().all(|(i, &v)| v == i);
            if !is_identity {
                current = self.tensor_permute(current, perm)?;
            }
        }

        // Sum over the trailing (contracted) dimensions from last to first
        for _ in 0..contract_dims.len() {
            let shape = self.tensor_shape(current)?;
            let last_dim = shape.len() - 1;
            current = self.tensor_sum_dim(current, last_dim)?;
        }

        // If output is scalar, ensure shape
        if output_idx.is_empty() {
            let shape = self.tensor_shape(current)?;
            if shape != [1] {
                current = self.tensor_reshape(current, vec![1])?;
            }
        }

        Ok(current)
    }

    fn einsum_binary(
        &mut self,
        lhs_idx: &[char],
        rhs_idx: &[char],
        output_idx: &[char],
        lhs: TensorNodeId,
        rhs: TensorNodeId,
        _dim_sizes: &std::collections::HashMap<char, usize>,
    ) -> Result<TensorNodeId, AutogradError> {
        let make_err = |reason: &'static str| {
            AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet { reason },
            ))
        };

        // Categorize indices:
        // - batch: appear in both inputs AND in output
        // - contract: appear in both inputs but NOT in output
        // - free_lhs: appear only in lhs (and in output)
        // - free_rhs: appear only in rhs (and in output)
        let lhs_set: std::collections::HashSet<char> = lhs_idx.iter().copied().collect();
        let rhs_set: std::collections::HashSet<char> = rhs_idx.iter().copied().collect();

        let mut batch_chars: Vec<char> = Vec::new();
        let mut contract_chars: Vec<char> = Vec::new();
        let mut free_lhs_chars: Vec<char> = Vec::new();
        let mut free_rhs_chars: Vec<char> = Vec::new();

        // Process lhs indices in order
        for &ch in lhs_idx {
            if rhs_set.contains(&ch) {
                if output_idx.contains(&ch) {
                    if !batch_chars.contains(&ch) {
                        batch_chars.push(ch);
                    }
                } else if !contract_chars.contains(&ch) {
                    contract_chars.push(ch);
                }
            } else if !free_lhs_chars.contains(&ch) {
                free_lhs_chars.push(ch);
            }
        }
        for &ch in rhs_idx {
            if !lhs_set.contains(&ch) && !free_rhs_chars.contains(&ch) {
                free_rhs_chars.push(ch);
            }
        }

        // Helpers to locate a subscript char's axis in the original index lists.
        // These chars are categorized FROM lhs_idx/rhs_idx, but return an error
        // if invariants are violated to avoid panics.
        let lhs_pos = |ch: &char| -> Result<usize, AutogradError> {
            lhs_idx
                .iter()
                .position(|c| c == ch)
                .ok_or_else(|| make_err("einsum: subscript char not found in lhs indices"))
        };
        let rhs_pos = |ch: &char| -> Result<usize, AutogradError> {
            rhs_idx
                .iter()
                .position(|c| c == ch)
                .ok_or_else(|| make_err("einsum: subscript char not found in rhs indices"))
        };

        // Build permutation for lhs: [batch..., free_lhs..., contract...]
        let mut lhs_perm =
            Vec::with_capacity(batch_chars.len() + free_lhs_chars.len() + contract_chars.len());
        for ch in batch_chars
            .iter()
            .chain(free_lhs_chars.iter())
            .chain(contract_chars.iter())
        {
            lhs_perm.push(lhs_pos(ch)?);
        }

        // Build permutation for rhs: [batch..., contract..., free_rhs...]
        let mut rhs_perm =
            Vec::with_capacity(batch_chars.len() + contract_chars.len() + free_rhs_chars.len());
        for ch in batch_chars
            .iter()
            .chain(contract_chars.iter())
            .chain(free_rhs_chars.iter())
        {
            rhs_perm.push(rhs_pos(ch)?);
        }

        let lhs_shape = self.tensor_shape(lhs)?;
        let rhs_shape = self.tensor_shape(rhs)?;

        // Compute dimension sizes after permutation
        let mut batch_size: usize = 1;
        for ch in &batch_chars {
            let dim = lhs_shape[lhs_pos(ch)?];
            batch_size = batch_size
                .checked_mul(dim)
                .ok_or_else(|| make_err("einsum: batch size overflow"))?;
        }
        let mut free_lhs_size: usize = 1;
        for ch in &free_lhs_chars {
            let dim = lhs_shape[lhs_pos(ch)?];
            free_lhs_size = free_lhs_size
                .checked_mul(dim)
                .ok_or_else(|| make_err("einsum: free lhs size overflow"))?;
        }
        let mut contract_size: usize = 1;
        for ch in &contract_chars {
            let dim = lhs_shape[lhs_pos(ch)?];
            contract_size = contract_size
                .checked_mul(dim)
                .ok_or_else(|| make_err("einsum: contract size overflow"))?;
        }
        let mut free_rhs_size: usize = 1;
        for ch in &free_rhs_chars {
            let dim = rhs_shape[rhs_pos(ch)?];
            free_rhs_size = free_rhs_size
                .checked_mul(dim)
                .ok_or_else(|| make_err("einsum: free rhs size overflow"))?;
        }

        // Permute tensors
        let mut lhs_p = lhs;
        if !lhs_perm.iter().enumerate().all(|(i, &v)| v == i) {
            lhs_p = self.tensor_permute(lhs_p, lhs_perm)?;
        }
        let mut rhs_p = rhs;
        if !rhs_perm.iter().enumerate().all(|(i, &v)| v == i) {
            rhs_p = self.tensor_permute(rhs_p, rhs_perm)?;
        }

        // Handle the case where there are no contractions (element-wise or outer product)
        if contract_chars.is_empty() && batch_chars.is_empty() {
            // Outer product case: reshape lhs to [M, 1], rhs to [1, N], matmul
            let m = free_lhs_size.max(1);
            let n = free_rhs_size.max(1);
            let lhs_2d = self.tensor_reshape(lhs_p, vec![m, 1])?;
            let rhs_2d = self.tensor_reshape(rhs_p, vec![1, n])?;
            let result = self.tensor_matmul(lhs_2d, rhs_2d)?;
            // Reshape to output shape
            let mut out_shape: Vec<usize> = Vec::new();
            for &ch in output_idx {
                if free_lhs_chars.contains(&ch) {
                    out_shape.push(lhs_shape[lhs_pos(&ch)?]);
                } else if free_rhs_chars.contains(&ch) {
                    out_shape.push(rhs_shape[rhs_pos(&ch)?]);
                }
            }
            if out_shape.is_empty() {
                out_shape.push(1);
            }
            return self.tensor_reshape(result, out_shape);
        }

        if contract_chars.is_empty() {
            // Batch + free only: element-wise multiply with broadcasting
            let m = free_lhs_size.max(1);
            let n = free_rhs_size.max(1);
            let lhs_3d = self.tensor_reshape(lhs_p, vec![batch_size, m, 1])?;
            let rhs_3d = self.tensor_reshape(rhs_p, vec![batch_size, 1, n])?;
            let result = self.tensor_bmm(lhs_3d, rhs_3d)?;
            let mut out_shape: Vec<usize> = Vec::new();
            for &ch in output_idx {
                if batch_chars.contains(&ch) || free_lhs_chars.contains(&ch) {
                    out_shape.push(lhs_shape[lhs_pos(&ch)?]);
                } else if free_rhs_chars.contains(&ch) {
                    out_shape.push(rhs_shape[rhs_pos(&ch)?]);
                }
            }
            if out_shape.is_empty() {
                out_shape.push(1);
            }
            return self.tensor_reshape(result, out_shape);
        }

        // General case with contraction
        let m = free_lhs_size.max(1);
        let k = contract_size.max(1);
        let n = free_rhs_size.max(1);

        let result = if batch_chars.is_empty() {
            // No batch: 2D matmul [M, K] @ [K, N] -> [M, N]
            let lhs_2d = self.tensor_reshape(lhs_p, vec![m, k])?;
            let rhs_2d = self.tensor_reshape(rhs_p, vec![k, n])?;
            self.tensor_matmul(lhs_2d, rhs_2d)?
        } else {
            // Batch: 3D bmm [B, M, K] @ [B, K, N] -> [B, M, N]
            let b = batch_size;
            let lhs_3d = self.tensor_reshape(lhs_p, vec![b, m, k])?;
            let rhs_3d = self.tensor_reshape(rhs_p, vec![b, k, n])?;
            self.tensor_bmm(lhs_3d, rhs_3d)?
        };

        // Reshape to output shape
        let mut out_shape: Vec<usize> = Vec::new();
        for &ch in output_idx {
            if batch_chars.contains(&ch)
                || free_lhs_chars.contains(&ch)
                || contract_chars.contains(&ch)
            {
                out_shape.push(lhs_shape[lhs_pos(&ch)?]);
            } else if free_rhs_chars.contains(&ch) {
                out_shape.push(rhs_shape[rhs_pos(&ch)?]);
            }
        }

        if out_shape.is_empty() {
            // Scalar output: already [B, M, N] = [1, 1, 1]
            let flat = self.tensor_reshape(result, vec![1])?;
            return Ok(flat);
        }

        self.tensor_reshape(result, out_shape)
    }

    /// Apply a custom autograd function.
    ///
    /// `forward_fn` receives a `&mut FunctionCtx` and input data (values + shapes),
    /// returns output (values, shape).
    ///
    /// `backward_fn` receives the saved context and incoming gradients,
    /// returns one `Option<Vec<f64>>` per input.
    pub fn tensor_apply_function<F, B>(
        &mut self,
        inputs: &[TensorNodeId],
        forward_fn: F,
        backward_fn: B,
    ) -> Result<TensorNodeId, AutogradError>
    where
        F: FnOnce(
            &mut FunctionCtx,
            &[(&[f64], &[usize])],
        ) -> Result<(Vec<f64>, Vec<usize>), AutogradError>,
        B: Fn(&FunctionCtx, &[&[f64]]) -> Result<Vec<Option<Vec<f64>>>, AutogradError>
            + Send
            + Sync
            + 'static,
    {
        self.tensor_tape
            .apply_function(inputs, forward_fn, backward_fn)
    }

    /// Cross product of two 3-element vectors.
    ///
    /// Both inputs must be 1D tensors of length 3.
    /// Returns a 1D tensor of length 3: c = a × b.
    pub fn tensor_cross(
        &mut self,
        a: TensorNodeId,
        b: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let a_shape = self.tensor_shape(a)?;
        let b_shape = self.tensor_shape(b)?;
        if a_shape != [3] || b_shape != [3] {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::ShapeMismatch {
                    lhs: a_shape,
                    rhs: b_shape,
                },
            )));
        }

        // Cross product is bilinear, so the Jacobian-vector products
        // are themselves cross products:
        //     grad_a = b × grad_c
        //     grad_b = grad_c × a
        // Wrap in tensor_apply_function with this analytical backward.
        // Save a and b for backward. Tracked under frankentorch-j2rj.
        self.tensor_apply_function(
            &[a, b],
            |ctx, inputs| {
                let (av, _a_shape) = inputs[0];
                let (bv, _b_shape) = inputs[1];
                let result = vec![
                    av[1] * bv[2] - av[2] * bv[1],
                    av[2] * bv[0] - av[0] * bv[2],
                    av[0] * bv[1] - av[1] * bv[0],
                ];
                ctx.save_for_backward(av.to_vec(), vec![3]);
                ctx.save_for_backward(bv.to_vec(), vec![3]);
                Ok((result, vec![3]))
            },
            |ctx, grad_outputs| {
                let g = grad_outputs[0];
                let saved = ctx.saved_tensors();
                let av = &saved[0];
                let bv = &saved[1];
                // grad_a = b × grad_c
                let grad_a = vec![
                    bv[1] * g[2] - bv[2] * g[1],
                    bv[2] * g[0] - bv[0] * g[2],
                    bv[0] * g[1] - bv[1] * g[0],
                ];
                // grad_b = grad_c × a
                let grad_b = vec![
                    g[1] * av[2] - g[2] * av[1],
                    g[2] * av[0] - g[0] * av[2],
                    g[0] * av[1] - g[1] * av[0],
                ];
                Ok(vec![Some(grad_a), Some(grad_b)])
            },
        )
    }

    /// Dot product along the last dimension (batched dot product).
    ///
    /// For 1D inputs: equivalent to `tensor_dot`.
    /// For N-D inputs: dot product along the last dimension, output has one fewer dim.
    pub fn tensor_vecdot(
        &mut self,
        a: TensorNodeId,
        b: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let a_shape = self.tensor_shape(a)?;
        let b_shape = self.tensor_shape(b)?;
        if a_shape != b_shape {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::ShapeMismatch {
                    lhs: a_shape.clone(),
                    rhs: b_shape,
                },
            )));
        }
        if a_shape.len() == 1 {
            return self.tensor_dot(a, b);
        }
        // For N-D: element-wise multiply then sum along last dim
        let prod = self.tensor_mul(a, b)?;
        let last_dim = a_shape.len() - 1;
        self.tensor_sum_dim(prod, last_dim)
    }

    /// Embed a 1D vector as the diagonal of a 2D matrix.
    ///
    /// `diag_embed([1,2,3])` produces `[[1,0,0],[0,2,0],[0,0,3]]`.
    /// `offset` controls which diagonal: 0=main, 1=super, -1=sub.
    pub fn tensor_diag_embed(
        &mut self,
        input: TensorNodeId,
        offset: i32,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        if shape.len() != 1 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::InvalidDimension {
                    dim: shape.len(),
                    ndim: 1,
                },
            )));
        }
        let k = shape[0];
        let abs_offset = offset.unsigned_abs() as usize;
        let n = Self::checked_add(k, abs_offset, "diag_embed: output size overflow")?;
        let numel = Self::checked_mul(n, n, "diag_embed: output size overflow")?;
        let _ = Self::checked_mul(
            numel,
            std::mem::size_of::<f64>(),
            "diag_embed: output size overflow",
        )?;

        // Forward is purely linear in the input — output[row, col] is
        // input[i] when (row, col) is on the requested diagonal,
        // 0 otherwise. Backward extracts the diagonal:
        //     grad_input[i] = grad_output[row, col]
        // for the same (row, col) the forward used. Wrap in
        // tensor_apply_function with this analytical backward.
        // Tracked under frankentorch-d180.
        let positive_offset = offset >= 0;
        self.tensor_apply_function(
            &[input],
            move |_ctx, inputs| {
                let (vals, _in_shape) = inputs[0];
                let mut result = vec![0.0_f64; n * n];
                for (i, &v) in vals.iter().enumerate().take(k) {
                    let (row, col) = if positive_offset {
                        (i, i + abs_offset)
                    } else {
                        (i + abs_offset, i)
                    };
                    result[row * n + col] = v;
                }
                Ok((result, vec![n, n]))
            },
            move |_ctx, grad_outputs| {
                let grad_y = grad_outputs[0];
                let mut grad_in = vec![0.0_f64; k];
                for (i, slot) in grad_in.iter_mut().enumerate().take(k) {
                    let (row, col) = if positive_offset {
                        (i, i + abs_offset)
                    } else {
                        (i + abs_offset, i)
                    };
                    *slot = grad_y[row * n + col];
                }
                Ok(vec![Some(grad_in)])
            },
        )
    }

    /// Return unique elements from a 1D tensor.
    ///
    /// If `sorted` is true (default), output is sorted ascending.
    /// If `return_inverse` is true, also returns index mapping input -> unique.
    /// If `return_counts` is true, also returns count of each unique value.
    pub fn tensor_unique(
        &mut self,
        input: TensorNodeId,
        sorted: bool,
        return_inverse: bool,
        return_counts: bool,
    ) -> Result<(TensorNodeId, Option<TensorNodeId>, Option<TensorNodeId>), AutogradError> {
        if self.tensor_requires_grad(input)? {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "unique: autograd not supported (set deduplication is non-differentiable). Tracked under frankentorch-gec0.",
                },
            )));
        }
        let vals = self.tensor_values(input)?;

        // Collect unique values preserving first-occurrence order.
        //
        // Use IEEE 754 `==` to match torch.unique / numpy.unique:
        //   * 0.0 == -0.0 is true → merged (PyTorch behaviour)
        //   * NaN == NaN is false → every NaN is its own unique entry
        //   * Distinct subnormals (e.g. 5e-324 vs 1e-323) compare !=
        //     and stay distinct
        //
        // The previous heuristic `(u - v).abs() < f64::EPSILON ||
        // (u.is_nan() && v.is_nan())` silently merged any pair of
        // values within machine epsilon — incorrectly fusing
        // subnormals whose absolute distance is well below f64::EPSILON
        // — and merged every NaN bit pattern into one entry, both of
        // which violate the "Equivalent to torch.unique" contract.
        let mut unique_vals: Vec<f64> = Vec::new();
        let mut inverse_indices: Vec<usize> = Vec::with_capacity(vals.len());

        for &v in &vals {
            let pos = unique_vals.iter().position(|&u| u == v);
            match pos {
                Some(idx) => inverse_indices.push(idx),
                None => {
                    inverse_indices.push(unique_vals.len());
                    unique_vals.push(v);
                }
            }
        }

        if sorted {
            // Sort unique values and remap inverse indices
            let mut order: Vec<usize> = (0..unique_vals.len()).collect();
            order.sort_by(|&a, &b| unique_vals[a].total_cmp(&unique_vals[b]));
            let mut remap = vec![0usize; unique_vals.len()];
            for (new_idx, &old_idx) in order.iter().enumerate() {
                remap[old_idx] = new_idx;
            }
            let sorted_vals: Vec<f64> = order.iter().map(|&i| unique_vals[i]).collect();
            unique_vals = sorted_vals;
            for idx in &mut inverse_indices {
                *idx = remap[*idx];
            }
        }

        let unique_len = unique_vals.len();
        let unique_node = self.tensor_variable(unique_vals, vec![unique_len], false)?;

        let inverse_node = if return_inverse {
            let inv_f64: Vec<f64> = inverse_indices.iter().map(|&i| i as f64).collect();
            let n = inv_f64.len();
            Some(self.tensor_variable(inv_f64, vec![n], false)?)
        } else {
            None
        };

        let counts_node = if return_counts {
            let mut counts = vec![0.0f64; unique_len];
            for &idx in &inverse_indices {
                counts[idx] += 1.0;
            }
            Some(self.tensor_variable(counts, vec![unique_len], false)?)
        } else {
            None
        };

        Ok((unique_node, inverse_node, counts_node))
    }

    /// Remove consecutive duplicate elements from a 1D tensor.
    ///
    /// Unlike `unique`, only removes adjacent duplicates (O(n) without sorting).
    pub fn tensor_unique_consecutive(
        &mut self,
        input: TensorNodeId,
        return_inverse: bool,
        return_counts: bool,
    ) -> Result<(TensorNodeId, Option<TensorNodeId>, Option<TensorNodeId>), AutogradError> {
        if self.tensor_requires_grad(input)? {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "unique_consecutive: autograd not supported (consecutive deduplication is non-differentiable). Tracked under frankentorch-gec0.",
                },
            )));
        }
        let vals = self.tensor_values(input)?;

        let mut unique_vals: Vec<f64> = Vec::new();
        let mut inverse_indices: Vec<usize> = Vec::with_capacity(vals.len());
        let mut counts: Vec<f64> = Vec::new();

        for &v in &vals {
            let is_duplicate = match unique_vals.last() {
                Some(last) => (last - v).abs() < f64::EPSILON || (last.is_nan() && v.is_nan()),
                None => false,
            };
            if !is_duplicate {
                unique_vals.push(v);
                counts.push(1.0);
            } else if let Some(count) = counts.last_mut() {
                *count += 1.0;
            } else {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "unique_consecutive: internal count state missing",
                    },
                )));
            }
            inverse_indices.push(unique_vals.len() - 1);
        }

        let unique_len = unique_vals.len();
        let unique_node = self.tensor_variable(unique_vals, vec![unique_len], false)?;

        let inverse_node = if return_inverse {
            let inv_f64: Vec<f64> = inverse_indices.iter().map(|&i| i as f64).collect();
            let n = inv_f64.len();
            Some(self.tensor_variable(inv_f64, vec![n], false)?)
        } else {
            None
        };

        let counts_node = if return_counts {
            Some(self.tensor_variable(counts, vec![unique_len], false)?)
        } else {
            None
        };

        Ok((unique_node, inverse_node, counts_node))
    }

    /// Count the number of occurrences of each value in a 1-D non-negative integer tensor.
    ///
    /// Equivalent to `torch.bincount(input, weights=None, minlength=0)`.
    /// Input values are truncated to integers. Negative values cause an error.
    /// If `weights` is provided, it must have the same length and the output
    /// accumulates weights instead of unit counts.
    pub fn tensor_bincount(
        &mut self,
        input: TensorNodeId,
        weights: Option<TensorNodeId>,
        minlength: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        let vals = self.tensor_values(input)?;
        let input_shape = self.tensor_shape(input)?;
        if input_shape.len() != 1 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "bincount: input must be 1-dimensional",
                },
            )));
        }

        if let Some(w) = weights {
            let w_shape = self.tensor_shape(w)?;
            if w_shape.len() != 1 || w_shape[0] != input_shape[0] {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "bincount: weights must be 1-D with same length as input",
                    },
                )));
            }
        }

        // Find max value to determine output size
        let mut max_val: Option<i64> = None;
        for &v in &vals {
            if !v.is_finite() || v != v.floor() {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "bincount: input must contain finite integer values",
                    },
                )));
            }
            let iv = v as i64;
            if iv < 0 {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "bincount: input must be non-negative",
                    },
                )));
            }
            let iv_u = iv as u128;
            if iv_u > usize::MAX as u128 {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "bincount: input value too large",
                    },
                )));
            }
            max_val = Some(max_val.map_or(iv, |cur| cur.max(iv)));
        }

        let out_len = match max_val {
            Some(m) => {
                let m_usize = usize::try_from(m).map_err(|_| {
                    AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "bincount: input value too large",
                        },
                    ))
                })?;
                let base = m_usize.checked_add(1).ok_or({
                    AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "bincount: output size overflow",
                        },
                    ))
                })?;
                base.max(minlength)
            }
            None => minlength, // empty input
        };
        let _ = Self::checked_mul(
            out_len,
            std::mem::size_of::<f64>(),
            "bincount output size overflow",
        )?;

        // Compose via tensor_scatter_add so gradients flow back to the
        // weights tensor when present. Tracked under frankentorch-9r3c.
        // Previous body extracted both input and weight values + rebuilt
        // a non-grad leaf, severing autograd through every weighted
        // bincount call (focal-loss-style class re-weighting, etc.).
        // The input (bin indices) is integer-valued and intrinsically
        // non-differentiable; only weights flow gradients.
        if vals.is_empty() {
            return self.tensor_variable(vec![0.0; out_len], vec![out_len], false);
        }
        let zeros = self.full(vec![out_len], 0.0, false)?;
        // input itself is the index tensor; reshape pass-through to
        // make the autograd contract clear (and so we can pass the
        // original requires_grad=false integer tensor as the index).
        if let Some(weights) = weights {
            self.tensor_scatter_add(zeros, 0, input, weights)
        } else {
            // Unweighted case: src = ones of same shape as input.
            let ones = self.full(vec![vals.len()], 1.0, false)?;
            self.tensor_scatter_add(zeros, 0, input, ones)
        }
    }

    /// Compute the histogram of a tensor.
    ///
    /// Equivalent to `torch.histc(input, bins=100, min=0, max=0)`.
    /// Divides the range `[min, max]` into `bins` equal-width bins and counts
    /// elements falling into each bin. If `min == max`, the range is set to
    /// `[input.min(), input.max()]`.
    ///
    /// Values outside `[min, max]` are *ignored* (not counted in any bin),
    /// matching PyTorch's `torch.histc` and NumPy's `numpy.histogram`. The
    /// upper boundary is inclusive: values exactly equal to `max` land in
    /// the last bin (`bins - 1`).
    pub fn tensor_histc(
        &mut self,
        input: TensorNodeId,
        bins: usize,
        min_val: f64,
        max_val: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        if self.tensor_requires_grad(input)? {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "histc: autograd not supported (integer counts are non-differentiable). Tracked under frankentorch-gec0.",
                },
            )));
        }
        if bins == 0 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "histc: bins must be > 0",
                },
            )));
        }
        if !min_val.is_finite() || !max_val.is_finite() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "histc: min and max must be finite",
                },
            )));
        }
        if min_val > max_val {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "histc: min must be <= max",
                },
            )));
        }

        let vals = self.tensor_values(input)?;
        for &v in &vals {
            if !v.is_finite() {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "histc: input values must be finite",
                    },
                )));
            }
        }

        let (lo, hi) = if (min_val - max_val).abs() < f64::EPSILON {
            // Auto-range from data
            let mut data_min = f64::INFINITY;
            let mut data_max = f64::NEG_INFINITY;
            for &v in &vals {
                if v < data_min {
                    data_min = v;
                }
                if v > data_max {
                    data_max = v;
                }
            }
            if data_min == data_max {
                (data_min - 0.5, data_max + 0.5)
            } else {
                (data_min, data_max)
            }
        } else {
            (min_val, max_val)
        };

        let mut counts = vec![0.0f64; bins];
        let bin_width = (hi - lo) / bins as f64;

        // Match PyTorch / numpy semantics: values outside [lo, hi] are
        // ignored (not counted in any bin). The upper boundary is
        // inclusive — values exactly equal to `hi` land in the last
        // bin (the floor((v-lo)/bin_width) computation maps `v == hi`
        // to bin `bins`, which we cap to `bins - 1`).
        //
        // Previously this clamped out-of-range values to the first /
        // last bin, which violated the "Equivalent to torch.histc"
        // contract: torch.histc(x=[-10, 0.5, 1.5, 100], bins=2,
        // min=0, max=2) returns [1, 1] (just the in-range elements),
        // not [2, 2].
        for &v in &vals {
            if v < lo || v > hi {
                continue;
            }
            #[allow(clippy::cast_sign_loss, clippy::cast_possible_truncation)]
            let raw_bin = ((v - lo) / bin_width) as usize;
            let bin = raw_bin.min(bins - 1);
            counts[bin] += 1.0;
        }

        self.tensor_variable(counts, vec![bins], false)
    }

    /// Create a block diagonal matrix from provided 2-D tensors.
    ///
    /// Equivalent to `torch.block_diag(*tensors)`. Each tensor is placed
    /// along the diagonal of the output matrix, with zeros elsewhere.
    /// 1-D tensors are treated as (1, N) matrices.
    pub fn tensor_block_diag(
        &mut self,
        tensors: &[TensorNodeId],
    ) -> Result<TensorNodeId, AutogradError> {
        if tensors.is_empty() {
            return self.tensor_variable(vec![], vec![0, 0], false);
        }

        // Pre-compute block (rows, cols), output total dimensions, and
        // (row_offset, col_offset) per block. The forward + backward
        // closures need both the per-block extents (to walk the block)
        // and the offsets (to map block coords ↔ output coords).
        // We also preserve the original input shape (1-D vs 2-D) so
        // gradients return as the same rank.
        let mut block_meta: Vec<(usize, usize, usize, usize, Vec<usize>)> =
            Vec::with_capacity(tensors.len());
        for &t in tensors {
            let shape = self.tensor_shape(t)?;
            let (rows, cols) = match shape.len() {
                1 => (1, shape[0]),
                2 => (shape[0], shape[1]),
                _ => {
                    return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "block_diag: all tensors must be 1-D or 2-D",
                        },
                    )));
                }
            };
            block_meta.push((rows, cols, 0, 0, shape.clone()));
        }
        // Fill row/col offsets sequentially.
        let mut row_offset = 0usize;
        let mut col_offset = 0usize;
        for entry in &mut block_meta {
            entry.2 = row_offset;
            entry.3 = col_offset;
            row_offset = Self::checked_add(row_offset, entry.0, "block_diag: output overflow")?;
            col_offset = Self::checked_add(col_offset, entry.1, "block_diag: output overflow")?;
        }
        let total_rows = row_offset;
        let total_cols = col_offset;
        let numel = Self::checked_mul(total_rows, total_cols, "block_diag: output overflow")?;
        let _ =
            Self::checked_mul(numel, std::mem::size_of::<f64>(), "block_diag: output overflow")?;

        // Forward + backward closures need the metadata at backward
        // time. tensor_apply_function captures via Send + Sync, so we
        // clone into the closures.
        let block_meta_fwd = block_meta.clone();
        let block_meta_bwd = block_meta.clone();
        self.tensor_apply_function(
            tensors,
            move |_ctx, inputs| {
                let mut data = vec![0.0_f64; total_rows * total_cols];
                for (i, (vals, _shape)) in inputs.iter().enumerate() {
                    let (rows, cols, row_off, col_off, _) = block_meta_fwd[i];
                    let expected = rows.checked_mul(cols).ok_or(AutogradError::Dispatch(
                        ft_dispatch::DispatchError::Key(
                            ft_dispatch::DispatchKeyError::IncompatibleSet {
                                reason: "block_diag: block size overflow",
                            },
                        ),
                    ))?;
                    if vals.len() != expected {
                        return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                            ft_dispatch::DispatchKeyError::IncompatibleSet {
                                reason: "block_diag: values length does not match shape",
                            },
                        )));
                    }
                    for r in 0..rows {
                        for c in 0..cols {
                            data[(row_off + r) * total_cols + col_off + c] = vals[r * cols + c];
                        }
                    }
                }
                Ok((data, vec![total_rows, total_cols]))
            },
            move |_ctx, grad_outputs| {
                let grad_y = grad_outputs[0];
                let mut grads: Vec<Option<Vec<f64>>> = Vec::with_capacity(block_meta_bwd.len());
                for (rows, cols, row_off, col_off, original_shape) in &block_meta_bwd {
                    let mut grad_block = vec![0.0_f64; rows * cols];
                    for r in 0..*rows {
                        for c in 0..*cols {
                            grad_block[r * cols + c] =
                                grad_y[(row_off + r) * total_cols + col_off + c];
                        }
                    }
                    // Original 1-D inputs deserve a flat-1-D gradient
                    // (rows == 1 && shape.len() == 1) — the storage
                    // is row-major so the same Vec works.
                    let _ = original_shape;
                    grads.push(Some(grad_block));
                }
                Ok(grads)
            },
        )
    }

    /// Generate a Vandermonde matrix from a 1-D input tensor.
    ///
    /// Equivalent to `torch.vander(x, N=None, increasing=False)`.
    /// If `n` is None, N = len(x). Each row `i` is `[x[i]^(N-1), ..., x[i]^0]`
    /// (decreasing) or `[x[i]^0, ..., x[i]^(N-1)]` (increasing).
    pub fn tensor_vander(
        &mut self,
        input: TensorNodeId,
        n: Option<usize>,
        increasing: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        if shape.len() != 1 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "vander: input must be 1-D",
                },
            )));
        }
        let rows = shape[0];
        let cols = n.unwrap_or(rows);
        if cols > i32::MAX as usize {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "vander: N too large",
                },
            )));
        }
        let numel = Self::checked_mul(rows, cols, "vander: output size overflow")?;
        let _ = Self::checked_mul(
            numel,
            std::mem::size_of::<f64>(),
            "vander: output size overflow",
        )?;

        // Forward: output[i, j] = x[i]^exp_j   where
        //     exp_j = j if increasing else cols-1-j.
        // Backward (each row depends only on x[i]):
        //     d output[i, j] / d x[i] = exp_j * x[i]^(exp_j - 1)   (0 when exp_j == 0)
        //     grad_input[i] = sum_j grad_output[i, j] * exp_j * x[i]^(exp_j - 1)
        // Save x for backward. Tracked under frankentorch-j3kg.
        self.tensor_apply_function(
            &[input],
            move |ctx, inputs| {
                let (vals, _in_shape) = inputs[0];
                if vals.len() != rows {
                    return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "vander: input length mismatch",
                        },
                    )));
                }
                let mut data = vec![0.0_f64; numel];
                for i in 0..rows {
                    for j in 0..cols {
                        let exp = if increasing { j } else { cols - 1 - j };
                        data[i * cols + j] = vals[i].powi(exp as i32);
                    }
                }
                ctx.save_for_backward(vals.to_vec(), vec![rows]);
                Ok((data, vec![rows, cols]))
            },
            move |ctx, grad_outputs| {
                let grad_y = grad_outputs[0];
                let saved = ctx.saved_tensors();
                let x_vals = &saved[0];
                let mut grad_in = vec![0.0_f64; rows];
                for i in 0..rows {
                    let xi = x_vals[i];
                    let mut acc = 0.0_f64;
                    for j in 0..cols {
                        let exp = if increasing { j } else { cols - 1 - j };
                        if exp == 0 {
                            // d x^0 / dx = 0; constant column contributes nothing.
                            continue;
                        }
                        let power = (exp - 1) as i32;
                        let coeff = exp as f64;
                        acc += grad_y[i * cols + j] * coeff * xi.powi(power);
                    }
                    grad_in[i] = acc;
                }
                Ok(vec![Some(grad_in)])
            },
        )
    }

    /// Create a complex tensor from magnitude and phase angle.
    ///
    /// Equivalent to `torch.polar(abs, angle)`.
    /// Returns a complex tensor where `real = abs * cos(angle)` and `imag = abs * sin(angle)`.
    ///
    /// Inputs should be F32 tensors (Complex64 output) or F64 tensors (Complex128 output).
    pub fn tensor_polar(
        &mut self,
        abs: TensorNodeId,
        angle: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        // Compute real = abs * cos(angle), imag = abs * sin(angle) via autograd ops
        let cos_angle = self.tensor_cos(angle)?;
        let sin_angle = self.tensor_sin(angle)?;
        let real = self.tensor_mul(abs, cos_angle)?;
        let imag = self.tensor_mul(abs, sin_angle)?;
        self.tensor_complex(real, imag)
    }

    /// Cartesian product of 1-D tensors.
    ///
    /// Equivalent to `torch.cartesian_prod(*tensors)`.
    /// Returns a 2-D tensor where each row is one element of the Cartesian product.
    pub fn tensor_cartesian_prod(
        &mut self,
        tensors: &[TensorNodeId],
    ) -> Result<TensorNodeId, AutogradError> {
        if tensors.is_empty() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "cartesian_prod: need at least one tensor",
                },
            )));
        }

        // Validate shapes + collect lengths.
        let mut lengths: Vec<usize> = Vec::with_capacity(tensors.len());
        for &t in tensors {
            let s = self.tensor_shape(t)?;
            if s.len() != 1 {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "cartesian_prod: all inputs must be 1-D",
                    },
                )));
            }
            lengths.push(s[0]);
        }
        let n_tensors = lengths.len();
        let mut total_rows = 1usize;
        for &len in &lengths {
            total_rows = total_rows.checked_mul(len).ok_or(AutogradError::Dispatch(
                ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "cartesian_prod: total row count overflow",
                    },
                ),
            ))?;
        }
        let _ = total_rows
            .checked_mul(n_tensors)
            .ok_or(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "cartesian_prod: output size overflow",
                },
            )))?;

        // Pre-compute the (row, k) → input_index_in_tensor_k mapping.
        // The forward gathers; the backward scatters. Tracked under
        // frankentorch-7ude.
        let mut mapping: Vec<Vec<usize>> = vec![Vec::with_capacity(total_rows); n_tensors];
        let mut indices = vec![0usize; n_tensors];
        for _ in 0..total_rows {
            for k in 0..n_tensors {
                mapping[k].push(indices[k]);
            }
            for k in (0..n_tensors).rev() {
                indices[k] += 1;
                if indices[k] < lengths[k] {
                    break;
                }
                indices[k] = 0;
            }
        }

        let mapping_for_fwd = mapping.clone();
        let mapping_for_bwd = mapping;
        let lengths_clone = lengths;
        let total_rows_c = total_rows;
        let n_tensors_c = n_tensors;

        self.tensor_apply_function(
            tensors,
            move |_ctx, inputs| {
                let mut result = Vec::with_capacity(total_rows_c * n_tensors_c);
                for row in 0..total_rows_c {
                    for (k, mapping_k) in mapping_for_fwd.iter().enumerate() {
                        let idx = mapping_k[row];
                        let (vals, _shape) = inputs[k];
                        result.push(vals[idx]);
                    }
                }
                Ok((result, vec![total_rows_c, n_tensors_c]))
            },
            move |_ctx, grad_outputs| {
                let g = grad_outputs[0];
                // For each input tensor k, scatter g[row, k] back to
                // grad_input_k[mapping[k][row]].
                let mut grads: Vec<Option<Vec<f64>>> = Vec::with_capacity(n_tensors_c);
                for k in 0..n_tensors_c {
                    let mut grad_k = vec![0.0_f64; lengths_clone[k]];
                    for row in 0..total_rows_c {
                        let i = mapping_for_bwd[k][row];
                        grad_k[i] += g[row * n_tensors_c + k];
                    }
                    grads.push(Some(grad_k));
                }
                Ok(grads)
            },
        )
    }

    /// All r-length combinations of elements from a 1-D tensor.
    ///
    /// Equivalent to `torch.combinations(input, r, with_replacement)`.
    /// Returns a 2-D tensor where each row is one combination.
    pub fn tensor_combinations(
        &mut self,
        input: TensorNodeId,
        r: usize,
        with_replacement: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        if shape.len() != 1 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "combinations: input must be 1-D",
                },
            )));
        }
        let n = shape[0];

        // Pre-compute the index-mapping: combo_indices is a flat list
        // of (input_position) for each (combo, slot_in_combo) cell of
        // the output. Use the same recursive enumeration as before
        // but track indices instead of values. The mapping is then
        // captured by the forward (gather) and backward (scatter)
        // closures in tensor_apply_function. Tracked under
        // frankentorch-d214 — previously this body extracted values,
        // built the output in plain f64, and rebuilt a non-grad leaf.
        let mut combo_indices: Vec<usize> = Vec::new();
        let mut current_indices: Vec<usize> = Vec::with_capacity(r);

        fn generate_idx(
            n: usize,
            r: usize,
            start: usize,
            current: &mut Vec<usize>,
            out: &mut Vec<usize>,
            with_replacement: bool,
        ) {
            if current.len() == r {
                out.extend_from_slice(current);
                return;
            }
            for i in start..n {
                current.push(i);
                let next = if with_replacement { i } else { i + 1 };
                generate_idx(n, r, next, current, out, with_replacement);
                current.pop();
            }
        }

        generate_idx(n, r, 0, &mut current_indices, &mut combo_indices, with_replacement);

        let num_combos = combo_indices.len().checked_div(r).unwrap_or(1);
        let total = Self::checked_mul(num_combos, r, "combinations output size overflow")?;

        if num_combos == 0 {
            return self.tensor_variable(vec![], vec![0, r], false);
        }

        let mapping_for_fwd = combo_indices.clone();
        let mapping_for_bwd = combo_indices;
        self.tensor_apply_function(
            &[input],
            move |_ctx, inputs| {
                let (vals, _shape) = inputs[0];
                let result: Vec<f64> = mapping_for_fwd.iter().map(|&i| vals[i]).collect();
                Ok((result, vec![num_combos, r]))
            },
            move |_ctx, grad_outputs| {
                let g = grad_outputs[0];
                let mut grad_in = vec![0.0_f64; n];
                for (out_pos, &in_pos) in mapping_for_bwd.iter().enumerate() {
                    grad_in[in_pos] += g[out_pos];
                }
                let _ = total; // keep total in scope for size validation above
                Ok(vec![Some(grad_in)])
            },
        )
    }

    /// Compute batched pairwise distance between two sets of vectors.
    ///
    /// Equivalent to `torch.cdist(x1, x2, p=2.0)`.
    /// x1: (B, P, M) or (P, M), x2: (B, R, M) or (R, M).
    /// Returns: (B, P, R) or (P, R) matrix of Lp distances.
    pub fn tensor_cdist(
        &mut self,
        x1: TensorNodeId,
        x2: TensorNodeId,
        p: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let x1_shape = self.tensor_shape(x1)?;
        let x2_shape = self.tensor_shape(x2)?;

        let (batch, p_dim, m1, r_dim, m2, batched) = match (x1_shape.len(), x2_shape.len()) {
            (2, 2) => (1, x1_shape[0], x1_shape[1], x2_shape[0], x2_shape[1], false),
            (3, 3) => {
                if x1_shape[0] != x2_shape[0] {
                    return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "cdist: batch dimensions must match",
                        },
                    )));
                }
                (
                    x1_shape[0],
                    x1_shape[1],
                    x1_shape[2],
                    x2_shape[1],
                    x2_shape[2],
                    true,
                )
            }
            _ => {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "cdist: inputs must be 2-D or 3-D with matching batch",
                    },
                )));
            }
        };

        if m1 != m2 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "cdist: last dimension (feature dim) must match",
                },
            )));
        }
        let m = m1;

        // Autograd path for finite p > 0: compose through broadcasted
        // sub + abs + pow + sum_dim + pow. Tracked under
        // frankentorch-tdqo. p == 0 / p == +inf still fail-loud on
        // requires_grad (sister of frankentorch-0i8u behavior).
        if p.is_finite() && p > 0.0 && batch * p_dim * r_dim > 0 {
            let (x1_b, x2_b, expand_target, sum_dim_idx, out_shape) = if batched {
                // x1: [B, P, M], x2: [B, R, M]
                // x1_b: [B, P, 1, M], x2_b: [B, 1, R, M], target: [B, P, R, M]
                let x1_u = self.tensor_unsqueeze(x1, 2)?;
                let x2_u = self.tensor_unsqueeze(x2, 1)?;
                (
                    x1_u,
                    x2_u,
                    vec![batch, p_dim, r_dim, m],
                    3,
                    vec![batch, p_dim, r_dim],
                )
            } else {
                // x1: [P, M], x2: [R, M]
                // x1_b: [P, 1, M], x2_b: [1, R, M], target: [P, R, M]
                let x1_u = self.tensor_unsqueeze(x1, 1)?;
                let x2_u = self.tensor_unsqueeze(x2, 0)?;
                (
                    x1_u,
                    x2_u,
                    vec![p_dim, r_dim, m],
                    2,
                    vec![p_dim, r_dim],
                )
            };
            let x1_e = self.tensor_expand(x1_b, expand_target.clone())?;
            let x2_e = self.tensor_expand(x2_b, expand_target)?;
            let diff = self.tensor_sub(x1_e, x2_e)?;
            let abs_diff = self.tensor_abs(diff)?;
            let pow_diff = self.tensor_pow(abs_diff, p)?;
            let sum = self.tensor_sum_dim(pow_diff, sum_dim_idx)?;
            let result = self.tensor_pow(sum, 1.0 / p)?;
            // Reshape ensures the output shape contract matches the
            // original direct-path output (sum_dim already reduces
            // the right axis; we just need to confirm the shape).
            return self.tensor_reshape(result, out_shape);
        }

        if (p == f64::INFINITY || p == 0.0)
            && (self.tensor_tape.tensor_requires_grad(x1)?
                || self.tensor_tape.tensor_requires_grad(x2)?)
        {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "cdist: autograd is not yet implemented for p=0 or p=inf",
                },
            )));
        }

        // Non-grad fallback path for p == 0, p == inf, or empty output.
        let x1_vals = self.tensor_values(x1)?;
        let x2_vals = self.tensor_values(x2)?;

        let mut result = vec![0.0f64; batch * p_dim * r_dim];

        for b in 0..batch {
            let x1_base = b * p_dim * m;
            let x2_base = b * r_dim * m;
            let out_base = b * p_dim * r_dim;

            for i in 0..p_dim {
                for j in 0..r_dim {
                    let mut dist = 0.0f64;
                    if p == f64::INFINITY {
                        for k in 0..m {
                            let diff =
                                (x1_vals[x1_base + i * m + k] - x2_vals[x2_base + j * m + k]).abs();
                            if diff > dist {
                                dist = diff;
                            }
                        }
                    } else if p == 0.0 {
                        for k in 0..m {
                            let diff =
                                (x1_vals[x1_base + i * m + k] - x2_vals[x2_base + j * m + k]).abs();
                            if diff > f64::EPSILON {
                                dist += 1.0;
                            }
                        }
                    } else {
                        for k in 0..m {
                            let diff =
                                (x1_vals[x1_base + i * m + k] - x2_vals[x2_base + j * m + k]).abs();
                            dist += diff.powf(p);
                        }
                        dist = dist.powf(1.0 / p);
                    }
                    result[out_base + i * r_dim + j] = dist;
                }
            }
        }

        let out_shape = if batched {
            vec![batch, p_dim, r_dim]
        } else {
            vec![p_dim, r_dim]
        };
        self.tensor_variable(result, out_shape, false)
    }

    /// Compute pairwise distance between all pairs of row vectors in a 2-D tensor.
    ///
    /// Equivalent to `torch.nn.functional.pdist(input, p=2)`.
    /// Input: (N, M) tensor. Returns: 1-D tensor of N*(N-1)/2 distances.
    pub fn tensor_pdist(
        &mut self,
        input: TensorNodeId,
        p: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        if shape.len() != 2 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "pdist: input must be 2-D",
                },
            )));
        }
        let n = shape[0];
        let m = shape[1];
        let out_len = n * (n - 1) / 2;

        // For finite p > 0, compose through index_select + sub + abs +
        // pow + sum_dim + pow primitives so gradients flow to the
        // input. PyTorch's torch.nn.functional.pdist IS differentiable
        // for finite p > 0 (sub-gradient at the abs corner). p == 0
        // (counting metric) and p == +inf (max-routing) follow
        // separate paths and stay severed; for now they fail-loud
        // when requires_grad is set. Tracked under frankentorch-0i8u.
        if p.is_finite() && p > 0.0 && out_len > 0 {
            // Build row_i and row_j index tensors of length out_len.
            #[allow(clippy::cast_precision_loss)]
            let mut row_i_idx = Vec::with_capacity(out_len);
            #[allow(clippy::cast_precision_loss)]
            let mut row_j_idx = Vec::with_capacity(out_len);
            for i in 0..n {
                for j in (i + 1)..n {
                    row_i_idx.push(i as f64);
                    row_j_idx.push(j as f64);
                }
            }
            let row_i_t = self
                .tensor_tape
                .leaf(row_i_idx, vec![out_len], false)?;
            let row_j_t = self
                .tensor_tape
                .leaf(row_j_idx, vec![out_len], false)?;
            let left = self.tensor_index_select(input, 0, row_i_t)?;
            let right = self.tensor_index_select(input, 0, row_j_t)?;
            let diff = self.tensor_sub(left, right)?;
            let abs_diff = self.tensor_abs(diff)?;
            let pow_diff = self.tensor_pow(abs_diff, p)?;
            let sum = self.tensor_sum_dim(pow_diff, 1)?; // [out_len]
            return self.tensor_pow(sum, 1.0 / p);
        }

        if (p == f64::INFINITY || p == 0.0)
            && self.tensor_tape.tensor_requires_grad(input)?
        {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "pdist: autograd is not yet implemented for p=0 or p=inf",
                },
            )));
        }

        // Non-grad paths for p == 0, p == inf, or empty output —
        // fall back to the original direct computation.
        let vals = self.tensor_values(input)?;
        let mut result = Vec::with_capacity(out_len);
        for i in 0..n {
            for j in (i + 1)..n {
                let mut dist = 0.0f64;
                if p == f64::INFINITY {
                    for k in 0..m {
                        let diff = (vals[i * m + k] - vals[j * m + k]).abs();
                        if diff > dist {
                            dist = diff;
                        }
                    }
                } else if p == 0.0 {
                    for k in 0..m {
                        let diff = (vals[i * m + k] - vals[j * m + k]).abs();
                        if diff > f64::EPSILON {
                            dist += 1.0;
                        }
                    }
                } else {
                    for k in 0..m {
                        let diff = (vals[i * m + k] - vals[j * m + k]).abs();
                        dist += diff.powf(p);
                    }
                    dist = dist.powf(1.0 / p);
                }
                result.push(dist);
            }
        }

        self.tensor_variable(result, vec![out_len], false)
    }

    pub fn tensor_trace(&mut self, input: TensorNodeId) -> Result<TensorNodeId, AutogradError> {
        let (out, event) = self.tensor_tape.trace(input, self.mode())?;
        self.record_tensor_reduction_operation(&event);
        Ok(out)
    }

    pub fn tensor_lerp(
        &mut self,
        start: TensorNodeId,
        end: TensorNodeId,
        weight: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let (out, event) = self.tensor_tape.lerp(start, end, weight, self.mode())?;
        self.record_tensor_lerp_operation(&event);
        Ok(out)
    }

    pub fn tensor_addmm(
        &mut self,
        input: TensorNodeId,
        mat1: TensorNodeId,
        mat2: TensorNodeId,
        beta: f64,
        alpha: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let (out, event) = self
            .tensor_tape
            .addmm(input, mat1, mat2, beta, alpha, self.mode())?;
        self.record_tensor_addmm_operation(&event);
        Ok(out)
    }

    pub fn tensor_addmv(
        &mut self,
        input: TensorNodeId,
        mat: TensorNodeId,
        vec_input: TensorNodeId,
        beta: f64,
        alpha: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let (out, event) =
            self.tensor_tape
                .addmv(input, mat, vec_input, beta, alpha, self.mode())?;
        self.record_tensor_addmv_operation(&event);
        Ok(out)
    }

    /// Ensure `input` has at least 1 dimension.
    ///
    /// Equivalent to `torch.atleast_1d(input)`. 0-D scalars are
    /// reshaped to `[1]`; tensors with rank ≥ 1 are returned
    /// unchanged. Composes through autograd-aware tensor_reshape.
    /// Tracked under frankentorch-oi03.
    pub fn tensor_atleast_1d(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        if shape.is_empty() {
            self.tensor_reshape(input, vec![1])
        } else {
            Ok(input)
        }
    }

    /// Ensure `input` has at least 2 dimensions.
    ///
    /// Equivalent to `torch.atleast_2d(input)`. 0-D scalars become
    /// `[1, 1]`; 1-D `[N]` becomes `[1, N]`; tensors with rank ≥ 2
    /// are returned unchanged. Tracked under frankentorch-oi03.
    pub fn tensor_atleast_2d(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        match shape.len() {
            0 => self.tensor_reshape(input, vec![1, 1]),
            1 => {
                let n = shape[0];
                self.tensor_reshape(input, vec![1, n])
            }
            _ => Ok(input),
        }
    }

    /// Ensure `input` has at least 3 dimensions.
    ///
    /// Equivalent to `torch.atleast_3d(input)`. 0-D becomes `[1, 1, 1]`;
    /// 1-D `[N]` becomes `[1, N, 1]`; 2-D `[N, M]` becomes `[N, M, 1]`;
    /// tensors with rank ≥ 3 are returned unchanged. The asymmetric
    /// padding (left for the 1-D case, right for the 2-D case) matches
    /// PyTorch and numpy semantics. Tracked under frankentorch-oi03.
    pub fn tensor_atleast_3d(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        match shape.len() {
            0 => self.tensor_reshape(input, vec![1, 1, 1]),
            1 => {
                let n = shape[0];
                self.tensor_reshape(input, vec![1, n, 1])
            }
            2 => {
                let (n, m) = (shape[0], shape[1]);
                self.tensor_reshape(input, vec![n, m, 1])
            }
            _ => Ok(input),
        }
    }

    /// Matrix-vector product: `out = M @ v`.
    ///
    /// Equivalent to `torch.mv(input, vec_input)`. `input` must be a 2-D
    /// matrix of shape `[m, n]` and `vec_input` a 1-D vector of shape
    /// `[n]`; the result is a 1-D vector of shape `[m]`.
    /// Composes through autograd-aware tensor_reshape + tensor_matmul,
    /// so gradients flow to both inputs. Tracked under frankentorch-256l.
    pub fn tensor_mv(
        &mut self,
        input: TensorNodeId,
        vec_input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let m_shape = self.tensor_shape(input)?;
        let v_shape = self.tensor_shape(vec_input)?;
        if m_shape.len() != 2 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "mv: matrix input must be 2-D",
                },
            )));
        }
        if v_shape.len() != 1 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "mv: vector input must be 1-D",
                },
            )));
        }
        if m_shape[1] != v_shape[0] {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::ShapeMismatch {
                    lhs: m_shape.clone(),
                    rhs: v_shape.clone(),
                },
            )));
        }
        let n = v_shape[0];
        let m = m_shape[0];
        let v_2d = self.tensor_reshape(vec_input, vec![n, 1])?;
        let out_2d = self.tensor_matmul(input, v_2d)?;
        self.tensor_reshape(out_2d, vec![m])
    }

