    /// Return `true` when tensors have identical shape and element values.
    ///
    /// NaN values are considered unequal (matching PyTorch `torch.equal`).
    pub fn tensor_equal(
        &self,
        lhs: TensorNodeId,
        rhs: TensorNodeId,
    ) -> Result<bool, AutogradError> {
        let (lhs_values, lhs_meta) = self.tensor_values_meta(lhs)?;
        let (rhs_values, rhs_meta) = self.tensor_values_meta(rhs)?;

        if lhs_meta.shape() != rhs_meta.shape() || lhs_meta.dtype() != rhs_meta.dtype() {
            return Ok(false);
        }

        for (l, r) in lhs_values.iter().zip(rhs_values.iter()) {
            if l.is_nan() || r.is_nan() {
                return Ok(false);
            }
            if l != r {
                return Ok(false);
            }
        }
        Ok(true)
    }

    /// Return `true` when tensors are elementwise close within tolerance.
    ///
    /// Uses: `|a - b| <= atol + rtol * |b|`.
    pub fn tensor_allclose(
        &self,
        lhs: TensorNodeId,
        rhs: TensorNodeId,
        rtol: f64,
        atol: f64,
        equal_nan: bool,
    ) -> Result<bool, AutogradError> {
        if !rtol.is_finite() || !atol.is_finite() || rtol < 0.0 || atol < 0.0 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "allclose requires finite non-negative rtol and atol",
                },
            )));
        }

        let (lhs_values, lhs_meta) = self.tensor_values_meta(lhs)?;
        let (rhs_values, rhs_meta) = self.tensor_values_meta(rhs)?;

        if lhs_meta.shape() != rhs_meta.shape() || lhs_meta.dtype() != rhs_meta.dtype() {
            return Ok(false);
        }

        for (l, r) in lhs_values.iter().zip(rhs_values.iter()) {
            if l.is_nan() || r.is_nan() {
                if equal_nan && l.is_nan() && r.is_nan() {
                    continue;
                }
                return Ok(false);
            }

            if l.is_infinite() || r.is_infinite() {
                if l == r {
                    continue;
                }
                return Ok(false);
            }

            let tolerance = atol + rtol * r.abs();
            if (l - r).abs() > tolerance {
                return Ok(false);
            }
        }
        Ok(true)
    }

    /// Element-wise close-comparison mask, returning 0.0/1.0 tensor.
    ///
    /// Equivalent to `torch.isclose(lhs, rhs, rtol, atol, equal_nan)`.
    /// Each element is 1.0 when `|lhs - rhs| <= atol + rtol * |rhs|`,
    /// else 0.0. NaN handling follows PyTorch: NaN never closes to
    /// anything unless `equal_nan=true` and both sides are NaN. ±inf
    /// is close only to itself.
    ///
    /// Non-differentiable: fails loud on tracked inputs to avoid
    /// silently severing the autograd tape. Tracked under
    /// frankentorch-rvjs.
    pub fn tensor_isclose(
        &mut self,
        lhs: TensorNodeId,
        rhs: TensorNodeId,
        rtol: f64,
        atol: f64,
        equal_nan: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        if !rtol.is_finite() || !atol.is_finite() || rtol < 0.0 || atol < 0.0 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "isclose requires finite non-negative rtol and atol",
                },
            )));
        }
        if self.tensor_requires_grad(lhs)? || self.tensor_requires_grad(rhs)? {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "isclose: autograd not supported (close-comparison mask is non-differentiable). Tracked under frankentorch-rvjs.",
                },
            )));
        }

        let (lhs_values, lhs_meta) = self.tensor_values_meta(lhs)?;
        let (rhs_values, rhs_meta) = self.tensor_values_meta(rhs)?;
        if lhs_meta.shape() != rhs_meta.shape() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::ShapeMismatch {
                    lhs: lhs_meta.shape().to_vec(),
                    rhs: rhs_meta.shape().to_vec(),
                },
            )));
        }

        let result: Vec<f64> = lhs_values
            .iter()
            .zip(rhs_values.iter())
            .map(|(&l, &r)| {
                if l.is_nan() || r.is_nan() {
                    if equal_nan && l.is_nan() && r.is_nan() {
                        1.0
                    } else {
                        0.0
                    }
                } else if l.is_infinite() || r.is_infinite() {
                    if l == r {
                        1.0
                    } else {
                        0.0
                    }
                } else {
                    let tolerance = atol + rtol * r.abs();
                    if (l - r).abs() <= tolerance {
                        1.0
                    } else {
                        0.0
                    }
                }
            })
            .collect();
        let shape = lhs_meta.shape().to_vec();
        self.tensor_variable(result, shape, false)
    }

    pub fn tensor_sum(&mut self, input: TensorNodeId) -> Result<TensorNodeId, AutogradError> {
        let (out, event) = self.tensor_tape.sum(input, self.mode())?;
        self.record_tensor_reduction_operation(&event);
        Ok(out)
    }

    pub fn tensor_mean(&mut self, input: TensorNodeId) -> Result<TensorNodeId, AutogradError> {
        let (out, event) = self.tensor_tape.mean(input, self.mode())?;
        self.record_tensor_reduction_operation(&event);
        Ok(out)
    }

    /// NaN-aware sum: equivalent to `torch.nansum(input)`.
    ///
    /// Treats NaN values as 0 contribution. ±inf values pass through
    /// unchanged (matching PyTorch behavior — only NaN is masked).
    /// Composes through tensor_isnan + tensor_where + tensor_sum,
    /// so gradients flow only to non-NaN positions (the where
    /// routes the upstream gradient to the all-zero constant tensor
    /// at NaN positions, which has no requires_grad). Tracked under
    /// frankentorch-8q4o.
    pub fn tensor_nansum(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        let zeros = self.full(shape, 0.0, false)?;
        let mask = self.tensor_isnan(input)?;
        let cleaned = self.tensor_where(mask, zeros, input)?;
        self.tensor_sum(cleaned)
    }

    /// NaN-aware mean: equivalent to `torch.nanmean(input)`.
    ///
    /// Divides `nansum(input)` by the count of non-NaN elements.
    /// ±inf are counted as non-NaN (matching PyTorch). If every
    /// element is NaN the divisor is zero and the output is NaN.
    /// Tracked under frankentorch-8q4o.
    pub fn tensor_nanmean(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        let numel: usize = shape.iter().product();
        let zeros = self.full(shape, 0.0, false)?;
        let mask = self.tensor_isnan(input)?;
        let cleaned = self.tensor_where(mask, zeros, input)?;
        let summed = self.tensor_sum(cleaned)?;
        // count_non_nan = numel - sum(isnan(x)). Read sum(mask) as a
        // plain f64 (the count itself is non-differentiable — its
        // value depends on the input's NaN pattern which is not part
        // of any smooth gradient flow). The divisor enters as a
        // tensor_div by a non-grad scalar, so the gradient on summed
        // scales by 1 / count which is what nanmean's backward
        // needs.
        let nan_count_t = self.tensor_sum(mask)?;
        let nan_count = self.tensor_values(nan_count_t)?[0];
        let count_non_nan = numel as f64 - nan_count;
        let summed_shape = self.tensor_shape(summed)?;
        let divisor = self.full(summed_shape, count_non_nan, false)?;
        self.tensor_div(summed, divisor)
    }

