    fn validate_index_tensor_values(
        input_shape: &[usize],
        dim: usize,
        index_values: &[f64],
    ) -> Result<(), AutogradError> {
        let Some(&dim_size) = input_shape.get(dim) else {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "index operation dimension out of bounds",
                },
            )));
        };

        let dim_size_i = isize::try_from(dim_size).map_err(|_| {
            AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "index operation dimension is out of range for platform isize",
                },
            ))
        })?;
        for &idx in index_values {
            let idx_i = Self::exact_integer_index_to_isize(
                idx,
                "index tensors must contain finite integer values",
            )?;
            if idx_i < -dim_size_i || idx_i >= dim_size_i {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "index tensor value out of bounds for input dimension",
                    },
                )));
            }
        }

        Ok(())
    }

    fn stft_window_values(
        &self,
        window: Option<TensorNodeId>,
        win_length: usize,
    ) -> Result<Vec<f64>, AutogradError> {
        match window {
            Some(window_node) => {
                if self.tensor_tape.tensor_requires_grad(window_node)? {
                    return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "stft/istft: autograd for window tensors is not supported",
                        },
                    )));
                }
                let window_tensor = self.tensor_tape.tensor(window_node)?;
                if window_tensor.meta().shape() != [win_length] {
                    return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "stft/istft: window must be 1-D with length win_length",
                        },
                    )));
                }
                match window_tensor.typed_storage() {
                    TensorStorage::F32(values) => {
                        Ok(values.iter().map(|&v| f64::from(v)).collect::<Vec<_>>())
                    }
                    TensorStorage::F64(values) => Ok(values.as_ref().clone()),
                    _ => Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "stft/istft: window must be float32 or float64",
                        },
                    ))),
                }
            }
            None => Ok(vec![1.0; win_length]),
        }
    }

    fn affine_grid_axis_coordinate(index: usize, size: usize, align_corners: bool) -> f64 {
        if size <= 1 {
            0.0
        } else if align_corners {
            -1.0 + 2.0 * index as f64 / (size - 1) as f64
        } else {
            -1.0 + (2.0 * index as f64 + 1.0) / size as f64
        }
    }

    fn grid_sampler_unnormalize(coord: f64, size: usize, align_corners: bool) -> f64 {
        if align_corners {
            ((coord + 1.0) * (size.saturating_sub(1)) as f64) / 2.0
        } else {
            ((coord + 1.0) * size as f64 - 1.0) / 2.0
        }
    }

    fn grid_sampler_reflect(coord: f64, size: usize, align_corners: bool) -> f64 {
        if size <= 1 {
            return 0.0;
        }
        let (low, high) = if align_corners {
            (0.0, (size - 1) as f64)
        } else {
            (-0.5, size as f64 - 0.5)
        };
        let span = high - low;
        if span == 0.0 {
            return 0.0;
        }
        let period = 2.0 * span;
        let mut shifted = (coord - low).rem_euclid(period);
        if shifted > span {
            shifted = period - shifted;
        }
        (low + shifted).clamp(0.0, (size - 1) as f64)
    }

    fn grid_sample_f64(input: &[f64], grid: &[f64], plan: GridSamplePlan) -> Vec<f64> {
        let mut output = vec![0.0; plan.batch * plan.channels * plan.out_h * plan.out_w];

        let sample_value = |n: usize, c: usize, y: isize, x: isize| -> f64 {
            if y < 0 || y >= plan.in_h as isize || x < 0 || x >= plan.in_w as isize {
                0.0
            } else {
                let idx =
                    ((n * plan.channels + c) * plan.in_h + y as usize) * plan.in_w + x as usize;
                input[idx]
            }
        };

        for n in 0..plan.batch {
            for h in 0..plan.out_h {
                for w in 0..plan.out_w {
                    let grid_base = ((n * plan.out_h + h) * plan.out_w + w) * 2;
                    let mut x = grid[grid_base];
                    let mut y = grid[grid_base + 1];
                    if x.is_nan() {
                        x = -1.0;
                    }
                    if y.is_nan() {
                        y = -1.0;
                    }

                    let mut ix = Self::grid_sampler_unnormalize(x, plan.in_w, plan.align_corners);
                    let mut iy = Self::grid_sampler_unnormalize(y, plan.in_h, plan.align_corners);
                    match plan.padding_mode {
                        GridSamplePaddingMode::Zeros => {}
                        GridSamplePaddingMode::Border => {
                            ix = ix.clamp(0.0, (plan.in_w.saturating_sub(1)) as f64);
                            iy = iy.clamp(0.0, (plan.in_h.saturating_sub(1)) as f64);
                        }
                        GridSamplePaddingMode::Reflection => {
                            ix = Self::grid_sampler_reflect(ix, plan.in_w, plan.align_corners);
                            iy = Self::grid_sampler_reflect(iy, plan.in_h, plan.align_corners);
                        }
                    }

                    for c in 0..plan.channels {
                        let value = match plan.mode {
                            GridSampleMode::Nearest => {
                                let nearest_x = ix.round() as isize;
                                let nearest_y = iy.round() as isize;
                                match plan.padding_mode {
                                    GridSamplePaddingMode::Zeros => {
                                        sample_value(n, c, nearest_y, nearest_x)
                                    }
                                    GridSamplePaddingMode::Border
                                    | GridSamplePaddingMode::Reflection => sample_value(
                                        n,
                                        c,
                                        nearest_y.clamp(0, plan.in_h as isize - 1),
                                        nearest_x.clamp(0, plan.in_w as isize - 1),
                                    ),
                                }
                            }
                            GridSampleMode::Bilinear => {
                                let x0 = ix.floor();
                                let y0 = iy.floor();
                                let x1 = x0 + 1.0;
                                let y1 = y0 + 1.0;
                                let wx1 = ix - x0;
                                let wy1 = iy - y0;
                                let wx0 = 1.0 - wx1;
                                let wy0 = 1.0 - wy1;
                                let v00 = sample_value(n, c, y0 as isize, x0 as isize);
                                let v01 = sample_value(n, c, y0 as isize, x1 as isize);
                                let v10 = sample_value(n, c, y1 as isize, x0 as isize);
                                let v11 = sample_value(n, c, y1 as isize, x1 as isize);
                                v00 * wx0 * wy0
                                    + v01 * wx1 * wy0
                                    + v10 * wx0 * wy1
                                    + v11 * wx1 * wy1
                            }
                        };
                        let out_idx = ((n * plan.channels + c) * plan.out_h + h) * plan.out_w + w;
                        output[out_idx] = value;
                    }
                }
            }
        }

        output
    }

    fn istft_reconstruct_f64(
        &self,
        spectrogram: Vec<ft_core::Complex128>,
        plan: IstftReconstructPlan<'_>,
    ) -> Vec<f64> {
        let output_len = if plan.frames == 0 {
            0
        } else {
            plan.n_fft + plan.hop_length * (plan.frames - 1)
        };
        let mut signal = vec![0.0; output_len];
        let mut envelope = vec![0.0; output_len];
        let scale = if plan.normalized {
            1.0 / (plan.n_fft as f64).sqrt()
        } else {
            1.0 / plan.n_fft as f64
        };

        for frame_idx in 0..plan.frames {
            let mut full_spectrum = vec![ft_core::Complex128::new(0.0, 0.0); plan.n_fft];
            if plan.onesided {
                for k in 0..plan.freq_bins {
                    full_spectrum[k] = spectrogram[k * plan.frames + frame_idx];
                }
                let upper = if plan.n_fft.is_multiple_of(2) {
                    plan.freq_bins.saturating_sub(1)
                } else {
                    plan.freq_bins
                };
                for k in 1..upper {
                    full_spectrum[plan.n_fft - k] = full_spectrum[k].conj();
                }
            } else {
                for k in 0..plan.n_fft {
                    full_spectrum[k] = spectrogram[k * plan.frames + frame_idx];
                }
            }

            let mut frame_time = vec![0.0; plan.n_fft];
            for (n, sample) in frame_time.iter_mut().enumerate() {
                let mut value = ft_core::Complex128::new(0.0, 0.0);
                for (k, coeff) in full_spectrum.iter().enumerate() {
                    let angle =
                        2.0 * std::f64::consts::PI * k as f64 * n as f64 / plan.n_fft as f64;
                    let twiddle = ft_core::Complex128::new(angle.cos(), angle.sin());
                    value += *coeff * twiddle;
                }
                *sample = value.re * scale;
            }

            let start = frame_idx * plan.hop_length;
            for i in 0..plan.window_values.len() {
                let sample = frame_time[plan.window_pad + i] * plan.window_values[i];
                signal[start + i] += sample;
                envelope[start + i] += plan.window_values[i] * plan.window_values[i];
            }
        }

        for (sample, norm) in signal.iter_mut().zip(envelope.iter()) {
            if *norm > 1e-12 {
                *sample /= *norm;
            }
        }

        let mut trimmed = if plan.center {
            let pad = plan.n_fft / 2;
            if signal.len() >= 2 * pad {
                signal[pad..signal.len() - pad].to_vec()
            } else {
                Vec::new()
            }
        } else {
            signal
        };

        if let Some(target_len) = plan.length {
            match trimmed.len().cmp(&target_len) {
                std::cmp::Ordering::Greater => trimmed.truncate(target_len),
                std::cmp::Ordering::Less => trimmed.resize(target_len, 0.0),
                std::cmp::Ordering::Equal => {}
            }
        }
        trimmed
    }

    pub fn tensor_index_select(
        &mut self,
        input: TensorNodeId,
        dim: usize,
        indices: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let input_shape = self.tensor_shape(input)?;
        let indices_data = self.tensor_tape.values(indices)?;
        Self::validate_index_tensor_values(&input_shape, dim, &indices_data)?;
        self.tensor_tape.index_select(input, dim, &indices_data)
    }

    /// Like `tensor_index_select`, but the input's gradient is also
    /// surfaced as a sparse COO tensor on the backward report
    /// (`TensorBackwardReport::sparse_gradient`). Only meaningful for
    /// `dim=0`; other dims fall back to the standard dense gradient.
    pub fn tensor_index_select_sparse(
        &mut self,
        input: TensorNodeId,
        dim: usize,
        indices: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let input_shape = self.tensor_shape(input)?;
        let indices_data = self.tensor_tape.values(indices)?;
        Self::validate_index_tensor_values(&input_shape, dim, &indices_data)?;
        self.tensor_tape
            .index_select_sparse(input, dim, &indices_data)
    }

    pub fn tensor_gather(
        &mut self,
        input: TensorNodeId,
        dim: usize,
        index: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let input_shape = self.tensor_shape(input)?;
        let index_data = self.tensor_tape.values(index)?;
        Self::validate_index_tensor_values(&input_shape, dim, &index_data)?;
        let index_shape = self.tensor_tape.tensor(index)?.meta().shape().to_vec();
        self.tensor_tape
            .gather(input, dim, &index_data, index_shape)
    }

    pub fn tensor_scatter(
        &mut self,
        input: TensorNodeId,
        dim: usize,
        index: TensorNodeId,
        src: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let input_shape = self.tensor_shape(input)?;
        let index_data = self.tensor_tape.values(index)?;
        Self::validate_index_tensor_values(&input_shape, dim, &index_data)?;
        let index_shape = self.tensor_tape.tensor(index)?.meta().shape().to_vec();
        let input_dtype = self.tensor_tape.dtype(input)?;
        let src_dtype = self.tensor_tape.dtype(src)?;
        if src_dtype != input_dtype {
            return Err(AutogradError::Dispatch(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "scatter requires input and src to have matching dtypes",
                }
                .into(),
            ));
        }
        let src_data = match input_dtype {
            DType::F64 => self.tensor_tape.values(src)?,
            DType::F32 => self
                .tensor_tape
                .values_f32(src)?
                .into_iter()
                .map(f64::from)
                .collect(),
            _ => {
                return Err(AutogradError::Dispatch(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "scatter requires f32 or f64 tensors",
                    }
                    .into(),
                ));
            }
        };
        self.tensor_tape
            .scatter(input, src, dim, &index_data, index_shape, &src_data)
    }

    pub fn tensor_scatter_add(
        &mut self,
        input: TensorNodeId,
        dim: usize,
        index: TensorNodeId,
        src: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let input_shape = self.tensor_shape(input)?;
        let index_data = self.tensor_tape.values(index)?;
        Self::validate_index_tensor_values(&input_shape, dim, &index_data)?;
        let index_shape = self.tensor_tape.tensor(index)?.meta().shape().to_vec();
        let input_dtype = self.tensor_tape.dtype(input)?;
        let src_dtype = self.tensor_tape.dtype(src)?;
        if src_dtype != input_dtype {
            return Err(AutogradError::Dispatch(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "scatter_add requires input and src to have matching dtypes",
                }
                .into(),
            ));
        }
        let src_data = match input_dtype {
            DType::F64 => self.tensor_tape.values(src)?,
            DType::F32 => self
                .tensor_tape
                .values_f32(src)?
                .into_iter()
                .map(f64::from)
                .collect(),
            _ => {
                return Err(AutogradError::Dispatch(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "scatter_add requires f32 or f64 tensors",
                    }
                    .into(),
                ));
            }
        };
        self.tensor_tape
            .scatter_add(input, src, dim, &index_data, index_shape, &src_data)
    }

    pub fn tensor_index_put(
        &mut self,
        input: TensorNodeId,
        indices: &[TensorNodeId],
        values: TensorNodeId,
        accumulate: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        let idx_data: Vec<Vec<f64>> = indices
            .iter()
            .map(|&idx| self.tensor_tape.values(idx))
            .collect::<Result<_, _>>()?;
        let input_dtype = self.tensor_tape.dtype(input)?;
        let values_dtype = self.tensor_tape.dtype(values)?;
        if values_dtype != input_dtype {
            return Err(AutogradError::Dispatch(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "index_put requires input and values to have matching dtypes",
                }
                .into(),
            ));
        }
        let vals_data = match input_dtype {
            DType::F64 => self.tensor_tape.values(values)?,
            DType::F32 => self
                .tensor_tape
                .values_f32(values)?
                .into_iter()
                .map(f64::from)
                .collect(),
            _ => {
                return Err(AutogradError::Dispatch(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "index_put requires f32 or f64 tensors",
                    }
                    .into(),
                ));
            }
        };
        self.tensor_tape
            .index_put(input, values, &idx_data, &vals_data, accumulate)
    }

    pub fn tensor_masked_fill(
        &mut self,
        input: TensorNodeId,
        mask: TensorNodeId,
        value: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        let fill_tensor = self.full(shape, value, false)?;
        self.tensor_where(mask, fill_tensor, input)
    }

    /// Accumulate `src` into `self` at positions specified by `index` along `dim`.
    ///
    /// Equivalent to `tensor.index_add_(dim, index, source)`.
    /// For each `i`, adds `src[i]` to `self[index[i]]` along `dim`.
    pub fn tensor_index_add(
        &mut self,
        input: TensorNodeId,
        dim: usize,
        index: TensorNodeId,
        src: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        let index_shape = self.tensor_shape(index)?;
        if index_shape.len() != 1 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "index_add: index tensor must be 1D",
                },
            )));
        }
        let index_len = index_shape[0];
        let idx_vals = self.tensor_values(index)?;
        let src_shape = self.tensor_shape(src)?;
        let input_dtype = self.tensor_tape.dtype(input)?;
        let src_dtype = self.tensor_tape.dtype(src)?;
        if src_dtype != input_dtype {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "index_add requires input and src to have matching dtypes",
                },
            )));
        }
        if src_shape.len() != shape.len() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "index_add: src rank must match input rank",
                },
            )));
        }
        for (dim_idx, &size) in shape.iter().enumerate() {
            if dim_idx != dim && src_shape[dim_idx] != size {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "index_add: src shape must match input shape except at dim",
                    },
                )));
            }
        }

        let ndim = shape.len();
        if dim >= ndim {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "index_add: dim out of range",
                },
            )));
        }

        let dim_size = shape[dim];
        let outer = Self::checked_shape_numel(&shape[..dim], "index_add: outer shape overflow")?;
        let inner =
            Self::checked_shape_numel(&shape[dim + 1..], "index_add: inner shape overflow")?;
        let src_dim_size = src_shape[dim];
        if src_dim_size != index_len {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "index_add: src dimension must match index length",
                },
            )));
        }
        let dim_size_i = isize::try_from(dim_size).map_err(|_| {
            AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "index_add: index dimension out of range for platform isize",
                },
            ))
        })?;
        let normalize_index = |idx_f: f64| -> Result<usize, AutogradError> {
            let idx_i = Self::exact_integer_index_to_isize(
                idx_f,
                "index_add: index values must be finite integers",
            )?;
            if idx_i < -dim_size_i || idx_i >= dim_size_i {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "index_add: index value out of range",
                    },
                )));
            }
            let wrapped = if idx_i < 0 { idx_i + dim_size_i } else { idx_i };
            usize::try_from(wrapped).map_err(|_| {
                AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "index_add: index value out of range",
                    },
                ))
            })
        };

        // Validate every supplied index up-front so the composition
        // below sees only well-formed indices. (tensor_scatter_add
        // performs its own validation but produces less specific
        // error messages.)
        for &idx_f in &idx_vals {
            normalize_index(idx_f)?;
        }
        if !matches!(input_dtype, DType::F64 | DType::F32) {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "index_add requires f32 or f64 tensors",
                },
            )));
        }

        // Compose index_add through tensor_scatter_add so the
        // autograd tape carries gradients to both `input` and `src`.
        // The previous body extracted values and rebuilt a fresh
        // requires_grad=false leaf, silently severing the tape — the
        // same severed-autograd pattern Scatter / ScatterAdd /
        // IndexPut had until 5d4b5a1 / 56c5165 / 692d90e.
        //
        // index_add(input, dim, idx_1d, src) writes
        //     output[..., idx_1d[r], ...] += src[..., r, ...]
        // for each r in 0..src_dim_size, broadcasting across every
        // outer/inner position. tensor_scatter_add already implements
        // exactly this when given an index tensor of the same shape
        // as src, so we just expand the 1-D `idx_1d` into a full
        // [outer, src_dim_size, inner] index where every element at
        // position (o, r, i) is `idx_1d[r]`.
        let expanded_numel = Self::checked_mul(
            Self::checked_mul(outer, src_dim_size, "index_add: expanded index outer overflow")?,
            inner,
            "index_add: expanded index inner overflow",
        )?;
        let mut expanded_idx_vals = Vec::with_capacity(expanded_numel);
        for _o in 0..outer {
            for &idx_f in &idx_vals {
                for _i in 0..inner {
                    expanded_idx_vals.push(idx_f);
                }
            }
        }
        let expanded_idx_node =
            self.tensor_tape.leaf(expanded_idx_vals, src_shape.clone(), false)?;

        // Note: tensor_scatter_add propagates gradients through both
        // `input` (passthrough) and `src` (gather). Output dtype
        // matches `input` dtype.
        self.tensor_scatter_add(input, dim, expanded_idx_node, src)
    }

    /// Copy `src` into `self` at positions specified by `index` along `dim`.
    ///
    /// Equivalent to `tensor.index_copy_(dim, index, source)`.
    pub fn tensor_index_copy(
        &mut self,
        input: TensorNodeId,
        dim: usize,
        index: TensorNodeId,
        src: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        let index_shape = self.tensor_shape(index)?;
        if index_shape.len() != 1 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "index_copy: index tensor must be 1D",
                },
            )));
        }
        let index_len = index_shape[0];
        let idx_vals = self.tensor_values(index)?;
        let src_shape = self.tensor_shape(src)?;
        let input_dtype = self.tensor_tape.dtype(input)?;
        let src_dtype = self.tensor_tape.dtype(src)?;
        if src_dtype != input_dtype {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "index_copy requires input and src to have matching dtypes",
                },
            )));
        }
        if src_shape.len() != shape.len() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "index_copy: src rank must match input rank",
                },
            )));
        }
        for (dim_idx, &size) in shape.iter().enumerate() {
            if dim_idx != dim && src_shape[dim_idx] != size {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "index_copy: src shape must match input shape except at dim",
                    },
                )));
            }
        }

        let ndim = shape.len();
        if dim >= ndim {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "index_copy: dim out of range",
                },
            )));
        }

        let dim_size = shape[dim];
        let outer = Self::checked_shape_numel(&shape[..dim], "index_copy: outer shape overflow")?;
        let inner =
            Self::checked_shape_numel(&shape[dim + 1..], "index_copy: inner shape overflow")?;
        let src_dim_size = src_shape[dim];
        if src_dim_size != index_len {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "index_copy: src dimension must match index length",
                },
            )));
        }
        let dim_size_i = isize::try_from(dim_size).map_err(|_| {
            AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "index_copy: index dimension out of range for platform isize",
                },
            ))
        })?;
        let normalize_index = |idx_f: f64| -> Result<usize, AutogradError> {
            let idx_i = Self::exact_integer_index_to_isize(
                idx_f,
                "index_copy: index values must be finite integers",
            )?;
            if idx_i < -dim_size_i || idx_i >= dim_size_i {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "index_copy: index value out of range",
                    },
                )));
            }
            let wrapped = if idx_i < 0 { idx_i + dim_size_i } else { idx_i };
            usize::try_from(wrapped).map_err(|_| {
                AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "index_copy: index value out of range",
                    },
                ))
            })
        };

        // Validate every supplied index up-front so the composition
        // below sees only well-formed indices.
        for &idx_f in &idx_vals {
            normalize_index(idx_f)?;
        }
        if !matches!(input_dtype, DType::F64 | DType::F32) {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "index_copy requires f32 or f64 tensors",
                },
            )));
        }

        // Compose index_copy through tensor_scatter (non-add) so the
        // autograd tape carries gradients through both `input` and
        // `src`. Same severed-autograd pattern fix as in
        // tensor_index_add (this commit) and the earlier Scatter /
        // ScatterAdd / IndexPut fixes.
        //
        // index_copy(input, dim, idx_1d, src) writes
        //     output[..., idx_1d[r], ...] = src[..., r, ...]
        // for each r, broadcasting across every outer/inner position.
        // tensor_scatter implements this with overwrite (and the
        // updated last-write semantics for duplicate indices, fixed
        // in this branch). We expand the 1-D `idx_1d` to a full
        // [outer, src_dim_size, inner] index where every element at
        // (o, r, i) is `idx_1d[r]`.
        let expanded_numel = Self::checked_mul(
            Self::checked_mul(
                outer,
                src_dim_size,
                "index_copy: expanded index outer overflow",
            )?,
            inner,
            "index_copy: expanded index inner overflow",
        )?;
        let mut expanded_idx_vals = Vec::with_capacity(expanded_numel);
        for _o in 0..outer {
            for &idx_f in &idx_vals {
                for _i in 0..inner {
                    expanded_idx_vals.push(idx_f);
                }
            }
        }
        let expanded_idx_node =
            self.tensor_tape.leaf(expanded_idx_vals, src_shape.clone(), false)?;

        // tensor_scatter propagates gradients through both `input`
        // (passthrough with overwritten positions zeroed) and `src`
        // (gather, last-write-wins on duplicates). Output dtype
        // matches `input` dtype.
        self.tensor_scatter(input, dim, expanded_idx_node, src)
    }

    /// Fill positions specified by `index` along `dim` with a scalar value.
    ///
    /// Equivalent to `tensor.index_fill_(dim, index, value)`.
    pub fn tensor_index_fill(
        &mut self,
        input: TensorNodeId,
        dim: usize,
        index: TensorNodeId,
        value: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        let index_shape = self.tensor_shape(index)?;
        if index_shape.len() != 1 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "index_fill: index tensor must be 1D",
                },
            )));
        }
        let idx_vals = self.tensor_values(index)?;
        let input_dtype = self.tensor_tape.dtype(input)?;

        let ndim = shape.len();
        if dim >= ndim {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "index_fill: dim out of range",
                },
            )));
        }

        let dim_size = shape[dim];
        let outer = Self::checked_shape_numel(&shape[..dim], "index_fill: outer shape overflow")?;
        let inner =
            Self::checked_shape_numel(&shape[dim + 1..], "index_fill: inner shape overflow")?;
        let dim_size_i = isize::try_from(dim_size).map_err(|_| {
            AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "index_fill: index dimension out of range for platform isize",
                },
            ))
        })?;
        let normalize_index = |idx_f: f64| -> Result<usize, AutogradError> {
            let idx_i = Self::exact_integer_index_to_isize(
                idx_f,
                "index_fill: index values must be finite integers",
            )?;
            if idx_i < -dim_size_i || idx_i >= dim_size_i {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "index_fill: index value out of range",
                    },
                )));
            }
            let wrapped = if idx_i < 0 { idx_i + dim_size_i } else { idx_i };
            usize::try_from(wrapped).map_err(|_| {
                AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "index_fill: index value out of range",
                    },
                ))
            })
        };

        // Validate every supplied index up-front so the composition
        // below sees only well-formed indices.
        for &idx_f in &idx_vals {
            normalize_index(idx_f)?;
        }
        if !matches!(input_dtype, DType::F64 | DType::F32) {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "index_fill requires f32 or f64 tensors",
                },
            )));
        }

        // Compose index_fill through tensor_scatter (non-add) with a
        // constant `src` tensor of the fill value. The previous body
        // extracted input values and rebuilt a requires_grad=false
        // leaf, silently severing the tape — same severed-autograd
        // pattern as the recently-fixed index_add / index_copy.
        //
        // Mathematically:
        //   output[..., idx_1d[r], ...] = value          (r in 0..idx_len)
        //   output[..., other,       ...] = input[...]
        //
        // tensor_scatter(input, dim, expanded_idx, src_const) does
        // exactly this when src_const is shaped like the indexed
        // region and uniformly equal to `value`. Backward correctness:
        //   grad_input gets passthrough with overwritten positions
        //     zeroed (the autograd-aware scatter we just built); this
        //     is what we want for index_fill since the filled
        //     positions no longer carry input's contribution.
        //   grad_src would be a gather of incoming, but src_const has
        //     requires_grad=false (it's a constant value), so that
        //     gradient is correctly dropped — no backprop into the
        //     scalar fill value.
        let idx_len = idx_vals.len();
        let expanded_numel = Self::checked_mul(
            Self::checked_mul(outer, idx_len, "index_fill: expanded index outer overflow")?,
            inner,
            "index_fill: expanded index inner overflow",
        )?;
        let mut expanded_idx_vals = Vec::with_capacity(expanded_numel);
        for _o in 0..outer {
            for &idx_f in &idx_vals {
                for _i in 0..inner {
                    expanded_idx_vals.push(idx_f);
                }
            }
        }
        let mut src_shape = shape.clone();
        src_shape[dim] = idx_len;
        let expanded_idx_node =
            self.tensor_tape.leaf(expanded_idx_vals, src_shape.clone(), false)?;

        let src_const = match input_dtype {
            DType::F64 => self.tensor_variable(vec![value; expanded_numel], src_shape, false)?,
            DType::F32 => {
                #[allow(clippy::cast_possible_truncation)]
                let value_f32 = value as f32;
                self.tensor_variable_f32(vec![value_f32; expanded_numel], src_shape, false)?
            }
            _ => unreachable!("dtype already validated above"),
        };

        self.tensor_scatter(input, dim, expanded_idx_node, src_const)
    }

    pub fn tensor_cat(
        &mut self,
        inputs: &[TensorNodeId],
        dim: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        let (out, event) = self.tensor_tape.cat(inputs, dim, self.mode())?;
        self.record_tensor_join_operation(&event);
        Ok(out)
    }

    pub fn tensor_stack(
        &mut self,
        inputs: &[TensorNodeId],
        dim: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        let (out, event) = self.tensor_tape.stack(inputs, dim, self.mode())?;
        self.record_tensor_join_operation(&event);
        Ok(out)
    }

