    pub fn tensor_expand(
        &mut self,
        input: TensorNodeId,
        target_shape: Vec<usize>,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_tape.expand(input, target_shape)
    }

    /// Broadcast `input` to `target_shape` with full broadcasting rules.
    ///
    /// Equivalent to `torch.broadcast_to(input, shape)`. Differs from
    /// `tensor_expand` in two ways:
    ///   - accepts a target shape with HIGHER rank than input;
    ///     prepends size-1 dims on the left to match rank.
    ///   - validates broadcast compatibility per dim: each input dim
    ///     must be either 1 or exactly the target dim.
    ///
    /// Composes through autograd-aware tensor_reshape + tensor_expand,
    /// so gradients flow unchanged. Tracked under frankentorch-h2zt.
    pub fn tensor_broadcast_to(
        &mut self,
        input: TensorNodeId,
        target_shape: Vec<usize>,
    ) -> Result<TensorNodeId, AutogradError> {
        let input_shape = self.tensor_shape(input)?;
        if input_shape.len() > target_shape.len() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "broadcast_to: target rank must be >= input rank",
                },
            )));
        }
        let prefix = target_shape.len() - input_shape.len();
        // Validate each input dim is broadcast-compatible with the
        // corresponding (right-aligned) target dim.
        for (i, &in_dim) in input_shape.iter().enumerate() {
            let tgt_dim = target_shape[prefix + i];
            if in_dim != tgt_dim && in_dim != 1 {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                    ft_kernel_cpu::KernelError::ShapeMismatch {
                        lhs: input_shape.clone(),
                        rhs: target_shape.clone(),
                    },
                )));
            }
        }
        // Prepend size-1 dims to match target rank, then expand.
        let mut padded_shape = vec![1usize; prefix];
        padded_shape.extend_from_slice(&input_shape);
        let reshaped = if padded_shape == input_shape {
            input
        } else {
            self.tensor_reshape(input, padded_shape)?
        };
        self.tensor_expand(reshaped, target_shape)
    }

    /// Broadcast `input` to match `other`'s shape.
    ///
    /// Equivalent to `torch.Tensor.expand_as(other)` — thin wrapper
    /// around `tensor_broadcast_to(input, other.shape)`. Tracked
    /// under frankentorch-h2zt.
    pub fn tensor_expand_as(
        &mut self,
        input: TensorNodeId,
        other: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let target_shape = self.tensor_shape(other)?;
        self.tensor_broadcast_to(input, target_shape)
    }

    pub fn tensor_split(
        &mut self,
        input: TensorNodeId,
        split_sizes: &[usize],
        dim: usize,
    ) -> Result<Vec<TensorNodeId>, AutogradError> {
        self.tensor_tape.split(input, split_sizes, dim)
    }

    pub fn tensor_chunk(
        &mut self,
        input: TensorNodeId,
        chunks: usize,
        dim: usize,
    ) -> Result<Vec<TensorNodeId>, AutogradError> {
        self.tensor_tape.chunk(input, chunks, dim)
    }

    pub fn tensor_unbind(
        &mut self,
        input: TensorNodeId,
        dim: usize,
    ) -> Result<Vec<TensorNodeId>, AutogradError> {
        let shape = self.tensor_shape(input)?;
        let ndim = shape.len();
        if dim >= ndim {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::InvalidDimension { dim, ndim },
            )));
        }
        let dim_size = shape[dim];
        let mut results = Vec::with_capacity(dim_size);
        for i in 0..dim_size {
            let narrowed = self.tensor_narrow(input, dim, i, 1)?;
            let squeezed = self.tensor_squeeze(narrowed, dim)?;
            results.push(squeezed);
        }
        Ok(results)
    }

    pub fn tensor_meshgrid(
        &mut self,
        inputs: &[TensorNodeId],
    ) -> Result<Vec<TensorNodeId>, AutogradError> {
        if inputs.is_empty() {
            return Ok(Vec::new());
        }
        let mut sizes = Vec::with_capacity(inputs.len());
        for &id in inputs {
            let shape = self.tensor_shape(id)?;
            if shape.len() != 1 {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                    ft_kernel_cpu::KernelError::ShapeMismatch {
                        lhs: shape,
                        rhs: vec![0],
                    },
                )));
            }
            sizes.push(shape[0]);
        }
        let ndim = sizes.len();
        let mut results = Vec::with_capacity(ndim);
        for (i, &id) in inputs.iter().enumerate() {
            // Reshape to have size 1 in all dims except dim i
            let mut reshape_dims = vec![1; ndim];
            reshape_dims[i] = sizes[i];
            let reshaped = self.tensor_reshape(id, reshape_dims)?;
            // Expand to full grid shape
            let expanded = self.tensor_expand(reshaped, sizes.clone())?;
            results.push(expanded);
        }
        Ok(results)
    }

    /// Generates a normalized 2-D sampling grid from affine transforms.
    pub fn tensor_affine_grid(
        &mut self,
        theta: TensorNodeId,
        output_size: Vec<usize>,
        align_corners: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        if output_size.len() != 4 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "affine_grid: only 2-D output_size [N, C, H, W] is supported",
                },
            )));
        }

        let theta_tensor = self.tensor_tape.tensor(theta)?;
        let theta_meta = theta_tensor.meta().clone();
        if theta_meta.shape().len() != 3 || theta_meta.shape()[1] != 2 || theta_meta.shape()[2] != 3
        {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "affine_grid: theta must have shape [N, 2, 3]",
                },
            )));
        }

        let batch = output_size[0];
        let out_h = output_size[2];
        let out_w = output_size[3];
        if theta_meta.shape()[0] != batch {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "affine_grid: theta batch must match output_size batch",
                },
            )));
        }

        let output_shape = vec![batch, out_h, out_w, 2];
        let numel =
            Self::checked_shape_numel(&output_shape, "affine_grid output shape volume overflow")?;

        // Autograd path: tensor_apply_function works on f64. Only
        // exposed for F64 theta — F32 theta with requires_grad=true
        // still hits the existing fail-loud guard below to preserve
        // dtype semantics. The forward is linear in theta (each grid
        // cell is t00*x + t01*y + t02 / t10*x + t11*y + t12), so the
        // backward is just the same accumulator with grad_grid in
        // place of the constant 1. Tracked under frankentorch-bfj5
        // (child of frankentorch-3v6e).
        if matches!(theta_tensor.typed_storage(), TensorStorage::F64(_))
            && self.tensor_tape.tensor_requires_grad(theta)?
        {
            let out_h_c = out_h;
            let out_w_c = out_w;
            let batch_c = batch;
            let output_shape_c = output_shape.clone();
            let align_corners_c = align_corners;
            let out_id = self.tensor_apply_function(
                &[theta],
                move |_ctx, inputs| {
                    let (theta_vals, _shape) = inputs[0];
                    let mut grid = Vec::with_capacity(numel);
                    for n in 0..batch_c {
                        let base = n * 6;
                        let t00 = theta_vals[base];
                        let t01 = theta_vals[base + 1];
                        let t02 = theta_vals[base + 2];
                        let t10 = theta_vals[base + 3];
                        let t11 = theta_vals[base + 4];
                        let t12 = theta_vals[base + 5];
                        for h in 0..out_h_c {
                            let y = Self::affine_grid_axis_coordinate(h, out_h_c, align_corners_c);
                            for w in 0..out_w_c {
                                let x =
                                    Self::affine_grid_axis_coordinate(w, out_w_c, align_corners_c);
                                grid.push(t00 * x + t01 * y + t02);
                                grid.push(t10 * x + t11 * y + t12);
                            }
                        }
                    }
                    Ok((grid, output_shape_c.clone()))
                },
                move |_ctx, grad_outputs| {
                    let grad_grid = grad_outputs[0];
                    // grad_theta has shape [batch, 2, 3], flat layout.
                    let mut grad_theta = vec![0.0_f64; batch_c * 2 * 3];
                    for n in 0..batch_c {
                        let base = n * 6;
                        for h in 0..out_h_c {
                            let y = Self::affine_grid_axis_coordinate(h, out_h_c, align_corners_c);
                            for w in 0..out_w_c {
                                let x =
                                    Self::affine_grid_axis_coordinate(w, out_w_c, align_corners_c);
                                let cell = (n * out_h_c * out_w_c + h * out_w_c + w) * 2;
                                let g0 = grad_grid[cell];
                                let g1 = grad_grid[cell + 1];
                                grad_theta[base] += g0 * x;
                                grad_theta[base + 1] += g0 * y;
                                grad_theta[base + 2] += g0;
                                grad_theta[base + 3] += g1 * x;
                                grad_theta[base + 4] += g1 * y;
                                grad_theta[base + 5] += g1;
                            }
                        }
                    }
                    Ok(vec![Some(grad_theta)])
                },
            )?;
            self.runtime.ledger_mut().record(
                EvidenceKind::Dispatch,
                format!(
                    "affine_grid theta={} out={} align_corners={align_corners} (autograd)",
                    theta.0, out_id.0
                ),
            );
            return Ok(out_id);
        }

        if self.tensor_tape.tensor_requires_grad(theta)? {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "affine_grid: autograd is only supported for F64 theta",
                },
            )));
        }

        match theta_tensor.typed_storage() {
            TensorStorage::F32(values) => {
                let mut grid = Vec::with_capacity(numel);
                for n in 0..batch {
                    let base = n * 6;
                    let t00 = f64::from(values[base]);
                    let t01 = f64::from(values[base + 1]);
                    let t02 = f64::from(values[base + 2]);
                    let t10 = f64::from(values[base + 3]);
                    let t11 = f64::from(values[base + 4]);
                    let t12 = f64::from(values[base + 5]);
                    for h in 0..out_h {
                        let y = Self::affine_grid_axis_coordinate(h, out_h, align_corners);
                        for w in 0..out_w {
                            let x = Self::affine_grid_axis_coordinate(w, out_w, align_corners);
                            grid.push((t00 * x + t01 * y + t02) as f32);
                            grid.push((t10 * x + t11 * y + t12) as f32);
                        }
                    }
                }
                let out = self.tensor_tape.leaf_tensor(
                    DenseTensor::from_typed_storage(
                        TensorMeta::from_shape(output_shape, DType::F32, theta_meta.device()),
                        TensorStorage::F32(Arc::new(grid)),
                    )?,
                    false,
                );
                self.runtime.ledger_mut().record(
                    EvidenceKind::Dispatch,
                    format!(
                        "affine_grid theta={} out={} align_corners={align_corners}",
                        theta.0, out.0
                    ),
                );
                Ok(out)
            }
            TensorStorage::F64(values) => {
                let mut grid = Vec::with_capacity(numel);
                for n in 0..batch {
                    let base = n * 6;
                    let t00 = values[base];
                    let t01 = values[base + 1];
                    let t02 = values[base + 2];
                    let t10 = values[base + 3];
                    let t11 = values[base + 4];
                    let t12 = values[base + 5];
                    for h in 0..out_h {
                        let y = Self::affine_grid_axis_coordinate(h, out_h, align_corners);
                        for w in 0..out_w {
                            let x = Self::affine_grid_axis_coordinate(w, out_w, align_corners);
                            grid.push(t00 * x + t01 * y + t02);
                            grid.push(t10 * x + t11 * y + t12);
                        }
                    }
                }
                let out = self.tensor_tape.leaf_tensor(
                    DenseTensor::from_typed_storage(
                        TensorMeta::from_shape(output_shape, DType::F64, theta_meta.device()),
                        TensorStorage::F64(Arc::new(grid)),
                    )?,
                    false,
                );
                self.runtime.ledger_mut().record(
                    EvidenceKind::Dispatch,
                    format!(
                        "affine_grid theta={} out={} align_corners={align_corners}",
                        theta.0, out.0
                    ),
                );
                Ok(out)
            }
            _ => Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "affine_grid: theta must be float32 or float64",
                },
            ))),
        }
    }

    /// Samples a 4-D `NCHW` input using a normalized 2-D grid.
    pub fn tensor_grid_sample(
        &mut self,
        input: TensorNodeId,
        grid: TensorNodeId,
        mode: GridSampleMode,
        padding_mode: GridSamplePaddingMode,
        align_corners: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        if self.tensor_tape.tensor_requires_grad(input)?
            || self.tensor_tape.tensor_requires_grad(grid)?
        {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "grid_sample: autograd is not supported",
                },
            )));
        }

        let input_tensor = self.tensor_tape.tensor(input)?;
        let grid_tensor = self.tensor_tape.tensor(grid)?;
        let input_meta = input_tensor.meta().clone();
        let grid_meta = grid_tensor.meta().clone();

        if input_meta.shape().len() != 4 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "grid_sample: only 4-D input [N, C, H, W] is supported",
                },
            )));
        }
        if grid_meta.shape().len() != 4 || grid_meta.shape()[3] != 2 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "grid_sample: grid must have shape [N, H, W, 2]",
                },
            )));
        }

        let batch = input_meta.shape()[0];
        let channels = input_meta.shape()[1];
        let in_h = input_meta.shape()[2];
        let in_w = input_meta.shape()[3];
        let out_batch = grid_meta.shape()[0];
        let out_h = grid_meta.shape()[1];
        let out_w = grid_meta.shape()[2];
        if batch != out_batch {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "grid_sample: input and grid batch dimensions must match",
                },
            )));
        }

        let grid_values = match grid_tensor.typed_storage() {
            TensorStorage::F32(values) => values.iter().map(|&v| f64::from(v)).collect::<Vec<_>>(),
            TensorStorage::F64(values) => values.as_ref().clone(),
            _ => {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "grid_sample: grid must be float32 or float64",
                    },
                )));
            }
        };

        let output_shape = vec![batch, channels, out_h, out_w];
        let plan = GridSamplePlan {
            batch,
            channels,
            in_h,
            in_w,
            out_h,
            out_w,
            mode,
            padding_mode,
            align_corners,
        };
        match input_tensor.typed_storage() {
            TensorStorage::F32(values) => {
                let input_values = values.iter().map(|&v| f64::from(v)).collect::<Vec<_>>();
                let output = Self::grid_sample_f64(&input_values, &grid_values, plan);
                let out = self.tensor_tape.leaf_tensor(
                    DenseTensor::from_typed_storage(
                        TensorMeta::from_shape(output_shape, DType::F32, input_meta.device()),
                        TensorStorage::F32(Arc::new(
                            output.into_iter().map(|v| v as f32).collect(),
                        )),
                    )?,
                    false,
                );
                self.runtime.ledger_mut().record(
                    EvidenceKind::Dispatch,
                    format!(
                        "grid_sample input={} grid={} out={} mode={mode:?} padding={padding_mode:?} align_corners={align_corners}",
                        input.0, grid.0, out.0
                    ),
                );
                Ok(out)
            }
            TensorStorage::F64(values) => {
                let output = Self::grid_sample_f64(values.as_ref(), &grid_values, plan);
                let out = self.tensor_tape.leaf_tensor(
                    DenseTensor::from_typed_storage(
                        TensorMeta::from_shape(output_shape, DType::F64, input_meta.device()),
                        TensorStorage::F64(Arc::new(output)),
                    )?,
                    false,
                );
                self.runtime.ledger_mut().record(
                    EvidenceKind::Dispatch,
                    format!(
                        "grid_sample input={} grid={} out={} mode={mode:?} padding={padding_mode:?} align_corners={align_corners}",
                        input.0, grid.0, out.0
                    ),
                );
                Ok(out)
            }
            _ => Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "grid_sample: input must be float32 or float64",
                },
            ))),
        }
    }

    pub fn tensor_diagonal(
        &mut self,
        input: TensorNodeId,
        offset: i64,
    ) -> Result<TensorNodeId, AutogradError> {
        let dtype = self.tensor_dtype(input)?;
        if !matches!(dtype, DType::F64 | DType::F32) {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "tensor_diagonal requires f32 or f64 tensors",
                },
            )));
        }
        let shape = self.tensor_shape(input)?;
        if shape.len() != 2 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::InvalidDimension {
                    dim: shape.len(),
                    ndim: 2,
                },
            )));
        }
        let m = shape[0];
        let n = shape[1];
        let (row_start, col_start, diag_len) = if offset >= 0 {
            let col_start = offset as usize;
            if col_start >= n {
                return match dtype {
                    DType::F64 => self.tensor_variable(vec![], vec![0], false),
                    DType::F32 => self.tensor_variable_f32(vec![], vec![0], false),
                    _ => unreachable!("dtype checked above"),
                };
            }
            let diag_len = m.min(n - col_start);
            (0, col_start, diag_len)
        } else {
            let row_start = (-offset) as usize;
            if row_start >= m {
                return match dtype {
                    DType::F64 => self.tensor_variable(vec![], vec![0], false),
                    DType::F32 => self.tensor_variable_f32(vec![], vec![0], false),
                    _ => unreachable!("dtype checked above"),
                };
            }
            let diag_len = n.min(m - row_start);
            (row_start, 0, diag_len)
        };
        // Extract diagonal elements using index_select on flattened tensor.
        match dtype {
            DType::F64 => {
                // Wrap in tensor_apply_function with diagonal-extraction
                // forward + scatter backward (the inverse of
                // diag_embed). Tracked under frankentorch-sirh.
                let n_c = n;
                let m_c = m;
                let row_start_c = row_start;
                let col_start_c = col_start;
                let diag_len_c = diag_len;
                self.tensor_apply_function(
                    &[input],
                    move |_ctx, inputs| {
                        let (vals, _shape) = inputs[0];
                        let mut diag_vals = Vec::with_capacity(diag_len_c);
                        for i in 0..diag_len_c {
                            diag_vals.push(vals[(row_start_c + i) * n_c + col_start_c + i]);
                        }
                        Ok((diag_vals, vec![diag_len_c]))
                    },
                    move |_ctx, grad_outputs| {
                        let g = grad_outputs[0];
                        let mut grad_in = vec![0.0_f64; m_c * n_c];
                        for i in 0..diag_len_c {
                            grad_in[(row_start_c + i) * n_c + col_start_c + i] = g[i];
                        }
                        Ok(vec![Some(grad_in)])
                    },
                )
            }
            DType::F32 => {
                if self.tensor_tape.tensor_requires_grad(input)? {
                    return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "tensor_diagonal: autograd is only supported for F64",
                        },
                    )));
                }
                let vals = self.tensor_tape.values_f32(input)?;
                let mut diag_vals = Vec::with_capacity(diag_len);
                for i in 0..diag_len {
                    diag_vals.push(vals[(row_start + i) * n + col_start + i]);
                }
                self.tensor_variable_f32(diag_vals, vec![diag_len], false)
            }
            _ => Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "tensor_diagonal requires f32 or f64 tensors",
                },
            ))),
        }
    }

    pub fn tensor_values(&self, node: TensorNodeId) -> Result<Vec<f64>, AutogradError> {
        self.tensor_tape.values(node)
    }

    /// Return both the contiguous values and metadata for a tensor node.
    pub fn tensor_values_meta(
        &self,
        node: TensorNodeId,
    ) -> Result<(Vec<f64>, TensorMeta), AutogradError> {
        let values = self.tensor_tape.values(node)?;
        let meta = self.tensor_tape.tensor_meta(node)?.clone();
        Ok((values, meta))
    }

    /// In-place subtraction: target = target - other.
    pub fn tensor_sub_(
        &mut self,
        target: TensorNodeId,
        other: TensorNodeId,
    ) -> Result<(), AutogradError> {
        self.validate_tensor_in_place_binary_compatibility(target, other)?;
        match self.tensor_tape.dtype(target)? {
            DType::F64 => {
                let target_vals = self.tensor_tape.values(target)?;
                let other_vals = self.tensor_tape.values(other)?;
                let new_values: Vec<f64> = target_vals
                    .iter()
                    .zip(other_vals.iter())
                    .map(|(a, b)| a - b)
                    .collect();
                self.tensor_tape.update_tensor_values(target, new_values)?;
            }
            DType::F32 => {
                let target_vals = self.tensor_tape.values_f32(target)?;
                let other_vals = self.tensor_tape.values_f32(other)?;
                let new_values: Vec<f32> = target_vals
                    .iter()
                    .zip(other_vals.iter())
                    .map(|(a, b)| a - b)
                    .collect();
                self.tensor_tape
                    .update_tensor_values_f32(target, new_values)?;
            }
            _ => {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: INPLACE_FLOAT_REASON,
                    },
                )));
            }
        }
        self.record_tensor_in_place_operation("sub_", target, Some(format!("other={}", other.0)));
        Ok(())
    }

