    #[test]
    fn vector_norm_l2_propagates_gradient() {
        // Regression for frankentorch-4yh9: previously extracted
        // tensor_values + rebuilt non-grad leaf, severing autograd
        // through every vector_norm call.
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let t = s.tensor_variable(vec![3.0, 4.0], vec![2], true).unwrap();
        let norm = s.tensor_linalg_vector_norm(t, 2.0).unwrap();
        let val = s.tensor_values(norm).unwrap()[0];
        assert!((val - 5.0).abs() < 1e-10);
        let report = s.tensor_backward(norm).unwrap();
        let grad = s
            .tensor_gradient(&report, t)
            .expect("input gradient should exist");
        // d/dx_i sqrt(x_0^2 + x_1^2) = x_i / norm. For [3, 4], norm=5:
        //   grad = [3/5, 4/5] = [0.6, 0.8]
        assert!((grad[0] - 0.6).abs() < 1e-10);
        assert!((grad[1] - 0.8).abs() < 1e-10);
    }

    #[test]
    fn vector_norm_l1_propagates_gradient() {
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let t = s.tensor_variable(vec![-3.0, 4.0], vec![2], true).unwrap();
        let norm = s.tensor_linalg_vector_norm(t, 1.0).unwrap();
        let report = s.tensor_backward(norm).unwrap();
        let grad = s.tensor_gradient(&report, t).expect("L1 grad");
        // d/dx_i |x_i| = sign(x_i): [-1, 1]
        assert!((grad[0] - (-1.0)).abs() < 1e-10);
        assert!((grad[1] - 1.0).abs() < 1e-10);
    }

    #[test]
    fn vector_norm_inf_propagates_gradient() {
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let t = s
            .tensor_variable(vec![-3.0, 4.0, -1.0], vec![3], true)
            .unwrap();
        let norm = s.tensor_linalg_vector_norm(t, f64::INFINITY).unwrap();
        let report = s.tensor_backward(norm).unwrap();
        let grad = s.tensor_gradient(&report, t).expect("L_inf grad");
        // max(|x|) = 4 at index 1 (positive). d/dx_1 |x_1| = sign(x_1) = +1;
        // others zero (max is differentiable only at the strict argmax).
        assert!((grad[1] - 1.0).abs() < 1e-10);
        assert!(grad[0].abs() < 1e-10);
        assert!(grad[2].abs() < 1e-10);
    }

    #[test]
    fn fft_ops_fail_loud_on_requires_grad() {
        // Regression for frankentorch-xszk: fft/ifft/rfft/irfft used
        // to silently sever autograd by extracting tensor_values
        // upstream of tensor_complex (whose downstream guard didn't
        // trigger because the rebuilt re/im leaves were non-grad).
        // Each now fails loud — matches the stft/istft pattern (3v6e).
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let real = s
            .tensor_variable(vec![1.0, 2.0, 3.0, 4.0], vec![4], true)
            .unwrap();
        let fft_err = s
            .tensor_fft(real, None)
            .expect_err("fft must fail loud on requires_grad");
        assert!(format!("{fft_err:?}").contains("autograd not supported"));
        let rfft_err = s
            .tensor_rfft(real, None)
            .expect_err("rfft must fail loud on requires_grad");
        assert!(format!("{rfft_err:?}").contains("autograd not supported"));

        // Build a complex tensor with no grad, then make a
        // requires_grad version via the autograd system (synthesize
        // by going through a real op chain that flips requires_grad)
        // — for simplicity, fft/rfft on real-grad input is the
        // exclusive entry point we care about; ifft/irfft accept
        // complex input so the guard fires before the dtype check.
        // Just verify the guard triggers on the requires_grad real
        // input plumbed through via tensor_complex's predecessor,
        // which reflects the practical training-time path.
    }

    #[test]
    fn linalg_svd_class_ops_fail_loud_on_requires_grad() {
        // Regression for frankentorch-rl4g: SVD-class linalg ops
        // (svd, svdvals, eigh, eigvalsh, qr, cholesky) used to
        // silently sever autograd by extracting tensor_values and
        // rebuilding non-grad leaves. Each now fails loud when
        // input requires_grad — matches the parking-lot pattern of
        // pvfk (det/slogdet) and 3v6e (stft/istft).
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let a = s
            .tensor_variable(vec![2.0, 0.5, 0.5, 1.0], vec![2, 2], true)
            .unwrap();

        let svd_err = s
            .tensor_linalg_svd(a, false)
            .expect_err("svd must fail loud on requires_grad");
        assert!(format!("{svd_err:?}").contains("autograd not supported"));

        let svdvals_err = s
            .tensor_linalg_svdvals(a)
            .expect_err("svdvals must fail loud on requires_grad");
        assert!(format!("{svdvals_err:?}").contains("autograd not supported"));

        let eigh_err = s
            .tensor_linalg_eigh(a)
            .expect_err("eigh must fail loud on requires_grad");
        assert!(format!("{eigh_err:?}").contains("autograd not supported"));

        let eigvalsh_err = s
            .tensor_linalg_eigvalsh(a)
            .expect_err("eigvalsh must fail loud on requires_grad");
        assert!(format!("{eigvalsh_err:?}").contains("autograd not supported"));

        let qr_err = s
            .tensor_linalg_qr(a, true)
            .expect_err("qr must fail loud on requires_grad");
        assert!(format!("{qr_err:?}").contains("autograd not supported"));

        let chol_err = s
            .tensor_linalg_cholesky(a, false)
            .expect_err("cholesky must fail loud on requires_grad");
        assert!(format!("{chol_err:?}").contains("autograd not supported"));
    }

