        // [1, 1, 2] -> [1, 1, 4] with align_corners=true
        let input = s
            .tensor_variable(vec![0.0, 1.0], vec![1, 1, 2], false)
            .unwrap();
        let out = s
            .tensor_interpolate(input, Some(vec![4]), None, "linear", Some(true))
            .unwrap();
