        let vals = s.tensor_values(out).unwrap();
        // Reflect: [3, 2, 1, 2, 3, 4, 3, 2]
        assert_eq!(vals, vec![3.0, 2.0, 1.0, 2.0, 3.0, 4.0, 3.0, 2.0]);
