    // ── Loss function tests ─────────────────────────────────────────────

    #[test]
    fn focal_loss_basic() {
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        // With gamma=0, alpha=0.5: both classes equally weighted
        let input = s.tensor_variable(vec![0.0, 0.0], vec![2], false).unwrap();
        let target = s.tensor_variable(vec![1.0, 0.0], vec![2], false).unwrap();
        let loss = s.focal_loss(input, target, 0.5, 0.0).unwrap();
        let val = s.tensor_values(loss).unwrap()[0];
        // sigmoid(0)=0.5, -0.5*log(0.5) = 0.5*0.693 = 0.347 for each, mean=0.347
        assert!((val - 0.347).abs() < 0.01, "focal_loss={val}");
    }

    #[test]
    fn focal_loss_propagates_gradient_through_input() {
        // Regression test for frankentorch-m6uk. focal_loss used to
        // extract values, compute the per-element formula in plain
        // f64, build a non-grad leaf, then take tensor_mean — the
        // tensor_mean preserved autograd from there but the prior
        // leaf had already severed it. After composing through
        // sigmoid + linear-blend-by-target + pow + log + mean, the
        // input's tape edge is preserved.
        //
        // Sanity test: well-behaved logits with binary target should
        // produce a non-zero finite gradient on input. We don't
        // assert exact values here because the focal-loss closed form
        // in the non-trivial gamma > 0 regime is messy; the
        // important thing is that the gradient propagates at all.
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let input = s.tensor_variable(vec![1.0, -1.0], vec![2], true).unwrap();
        let target = s.tensor_variable(vec![1.0, 0.0], vec![2], false).unwrap();
        let loss = s.focal_loss(input, target, 0.5, 2.0).unwrap();
        let report = s.tensor_backward(loss).unwrap();
        let grad = s
            .tensor_gradient(&report, input)
            .expect("focal_loss must propagate gradient through input");
        assert_eq!(grad.len(), 2);
        assert!(
            grad.iter().all(|g| g.is_finite()),
            "focal_loss gradient must be finite, got {grad:?}"
        );
        // Both entries should be meaningfully non-zero — the gamma=2
        // factor reduces magnitude but doesn't zero it for finite
        // logits.
        assert!(
            grad.iter().all(|&g| g.abs() > 1e-9),
            "focal_loss gradient should be non-zero on both entries, got {grad:?}"
        );
    }

    #[test]
    fn focal_loss_gamma_reduces_easy_examples() {
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        // High confidence correct prediction: sigmoid(5) ≈ 0.993
        let input = s.tensor_variable(vec![5.0], vec![1], false).unwrap();
        let target = s.tensor_variable(vec![1.0], vec![1], false).unwrap();
        let loss_g0 = s.focal_loss(input, target, 0.5, 0.0).unwrap();
        let val_g0 = s.tensor_values(loss_g0).unwrap()[0];

        let input2 = s.tensor_variable(vec![5.0], vec![1], false).unwrap();
        let target2 = s.tensor_variable(vec![1.0], vec![1], false).unwrap();
        let loss_g2 = s.focal_loss(input2, target2, 0.5, 2.0).unwrap();
        let val_g2 = s.tensor_values(loss_g2).unwrap()[0];

        assert!(
            val_g2 < val_g0,
            "gamma=2 should down-weight easy examples: g0={val_g0}, g2={val_g2}"
        );
    }

    #[test]
    fn poisson_nll_loss_basic() {
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        // log_input=true: loss = exp(input) - target * input
        let input = s.tensor_variable(vec![1.0, 2.0], vec![2], false).unwrap();
        let target = s.tensor_variable(vec![1.0, 1.0], vec![2], false).unwrap();
        let loss = s
            .poisson_nll_loss(input, target, true, false, 1e-8)
            .unwrap();
        let val = s.tensor_values(loss).unwrap()[0];
        // mean((e^1 - 1*1) + (e^2 - 1*2)) / 2 = ((e-1) + (e^2-2)) / 2
        let expected = ((std::f64::consts::E - 1.0) + (std::f64::consts::E.powi(2) - 2.0)) / 2.0;
        assert!(
            (val - expected).abs() < 1e-8,
            "poisson_nll={val}, expected={expected}"
        );
    }

    #[test]
    fn poisson_nll_loss_propagates_gradient_through_input() {
        // Regression test for frankentorch-zl3n. poisson_nll_loss
        // used to extract values, compute the per-element loss in
        // plain f64, build a non-grad leaf, then take tensor_mean —
        // the tensor_mean preserved autograd from there but the
        // prior leaf had already severed it.
        //
        // Forward (log_input=true):
        //   loss_i = exp(input_i) - target_i * input_i
        //   loss   = mean over i
        // Backward:
        //   d loss / d input_i = (1/n) * (exp(input_i) - target_i)
        //
        // For input = [1, 2], target = [1, 1]:
        //   grad_0 = (e - 1) / 2 ≈ 0.8591
        //   grad_1 = (e^2 - 1) / 2 ≈ 3.1945
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let input = s.tensor_variable(vec![1.0, 2.0], vec![2], true).unwrap();
        let target = s.tensor_variable(vec![1.0, 1.0], vec![2], false).unwrap();
        let loss = s
            .poisson_nll_loss(input, target, true, false, 1e-8)
            .unwrap();
        let report = s.tensor_backward(loss).unwrap();
        let grad = s
            .tensor_gradient(&report, input)
            .expect("poisson_nll_loss must propagate gradient through input");
        let expected = [
            (1.0_f64.exp() - 1.0) / 2.0,
            (2.0_f64.exp() - 1.0) / 2.0,
        ];
        for (i, (&g, &e)) in grad.iter().zip(expected.iter()).enumerate() {
            assert!(
                (g - e).abs() < 1e-12,
                "poisson_nll grad[{i}] = {g}, expected {e}"
            );
        }
    }

    #[test]
    fn gaussian_nll_loss_basic() {
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        // Perfect prediction with variance 1: loss = 0.5 * log(1) + 0 = 0
        let input = s.tensor_variable(vec![1.0], vec![1], false).unwrap();
        let target = s.tensor_variable(vec![1.0], vec![1], false).unwrap();
        let var = s.tensor_variable(vec![1.0], vec![1], false).unwrap();
        let loss = s
            .gaussian_nll_loss(input, target, var, false, 1e-6)
            .unwrap();
        let val = s.tensor_values(loss).unwrap()[0];
        assert!(
            val.abs() < 1e-8,
            "perfect prediction should have ~0 loss, got {val}"
        );
    }

    #[test]
    fn gaussian_nll_loss_propagates_gradient_through_input_and_var() {
        // Regression test for frankentorch-vjow.
        // gaussian_nll_loss used to extract values, compute the
        // per-element loss in plain f64, and rebuild a non-grad leaf —
        // silently severing autograd through input / target / var.
        // After composing through clamp_min/log/sub/mul/div/mean
        // primitives, gradients flow.
        //
        // Forward (no full, no clamp triggering since var > eps):
        //   loss_i = 0.5 * (log(v_i) + (input_i - target_i)^2 / v_i)
        //   loss   = mean(loss_i)
        // Backward at non-clamped points:
        //   d loss / d input_i = (1/n) * (input_i - target_i) / v_i
        //   d loss / d var_i   = (1/n) * 0.5 * (1/v_i - (input_i - target_i)^2 / v_i^2)
        //
        // For input = [2.0], target = [1.0], var = [4.0]:
        //   diff = 1, diff^2 = 1, v = 4
        //   loss = 0.5 * (log(4) + 0.25) = 0.5 * (1.3863 + 0.25) = 0.8181
        //   grad_input = (1/1) * 1/4 = 0.25
        //   grad_var   = 0.5 * (1/4 - 1/16) = 0.5 * (0.25 - 0.0625) = 0.09375
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let input = s.tensor_variable(vec![2.0], vec![1], true).unwrap();
        let target = s.tensor_variable(vec![1.0], vec![1], false).unwrap();
        let var = s.tensor_variable(vec![4.0], vec![1], true).unwrap();
        let loss = s
            .gaussian_nll_loss(input, target, var, false, 1e-6)
            .unwrap();
        let report = s.tensor_backward(loss).unwrap();
        let grad_input = s
            .tensor_gradient(&report, input)
            .expect("gaussian_nll_loss must propagate gradient through input");
        let grad_var = s
            .tensor_gradient(&report, var)
            .expect("gaussian_nll_loss must propagate gradient through var");
        assert!((grad_input[0] - 0.25).abs() < 1e-12, "grad_input[0] = {}", grad_input[0]);
        assert!(
            (grad_var[0] - 0.09375).abs() < 1e-12,
            "grad_var[0] = {}",
            grad_var[0]
        );
    }

    #[test]
    fn soft_margin_loss_basic() {
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        // Correctly classified: target=1, input=large positive -> low loss
        let input = s.tensor_variable(vec![5.0, -5.0], vec![2], false).unwrap();
        let target = s.tensor_variable(vec![1.0, -1.0], vec![2], false).unwrap();
        let loss = s.soft_margin_loss(input, target).unwrap();
        let val = s.tensor_values(loss).unwrap()[0];
        // log(1 + exp(-5)) ≈ 0.0067 for both, mean ≈ 0.0067
        assert!(val < 0.01, "well-classified should have low loss: {val}");
    }

    #[test]
    fn soft_margin_loss_propagates_gradient_through_input() {
        // Regression test for frankentorch-tr2a. soft_margin_loss
        // used to extract values, compute the per-element loss in
        // plain f64, and build a requires_grad=false leaf — the
        // subsequent tensor_mean was autograd-aware but the prior
        // leaf had already severed the tape. After composing
        // through tensor_neg + tensor_mul + tensor_relu + tensor_abs +
        // tensor_log1p + tensor_exp + tensor_add, gradients flow.
        //
        // Forward: soft_margin(x, t) = log1p(exp(-t*x))
        // Backward (smooth interior, away from x*t = 0):
        //   d/dx = -t * sigmoid(-t*x) = -t / (1 + exp(t*x))
        // For input = [1.0, -1.0], target = [1.0, -1.0]:
        //   At (x=1, t=1):  d/dx = -1 / (1 + exp(1)) = -1 / 3.7183 ≈ -0.26894
        //   At (x=-1, t=-1): d/dx = -(-1) / (1 + exp(-1*1)) = 1 / 3.7183 ≈ -0.26894
        //     Wait: t = -1, so d/dx = -(-1) / (1 + exp((-1)*(-1))) = 1 / (1 + e) ≈ 0.26894
        // After mean (1/2 factor):
        //   grad = [-0.13447, 0.13447]
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let input = s.tensor_variable(vec![1.0, -1.0], vec![2], true).unwrap();
        let target = s.tensor_variable(vec![1.0, -1.0], vec![2], false).unwrap();
        let loss = s.soft_margin_loss(input, target).unwrap();
        let report = s.tensor_backward(loss).unwrap();
        let grad = s
            .tensor_gradient(&report, input)
            .expect("soft_margin_loss must propagate gradient through input");
        let inv_one_plus_e = 1.0 / (1.0 + 1.0_f64.exp());
        let expected = [-inv_one_plus_e / 2.0, inv_one_plus_e / 2.0];
        for (i, (&g, &e)) in grad.iter().zip(expected.iter()).enumerate() {
            assert!(
                (g - e).abs() < 1e-12,
                "soft_margin_loss grad[{i}] = {g}, expected {e}"
            );
        }
    }

    #[test]
    fn multi_margin_loss_basic() {
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        // input = [[3, 1, 0]], target = [0] -> correct class has highest score
        let input = s
            .tensor_variable(vec![3.0, 1.0, 0.0], vec![1, 3], false)
            .unwrap();
        let target = s.tensor_variable(vec![0.0], vec![1], false).unwrap();
        let loss = s.multi_margin_loss(input, target, 1.0, 1.0).unwrap();
        let val = s.tensor_values(loss).unwrap()[0];
        // max(0, 1-3+1) + max(0, 1-3+0) = 0 + 0 = 0
        assert!(
            val.abs() < 1e-10,
            "correct prediction should give 0 loss: {val}"
        );
    }

    #[test]
    fn multi_margin_loss_misclassified() {
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        // input = [[0, 3]], target = [0] -> wrong class has highest score
        let input = s
            .tensor_variable(vec![0.0, 3.0], vec![1, 2], false)
            .unwrap();
        let target = s.tensor_variable(vec![0.0], vec![1], false).unwrap();
        let loss = s.multi_margin_loss(input, target, 1.0, 1.0).unwrap();
        let val = s.tensor_values(loss).unwrap()[0];
        // max(0, 1-0+3) = 4, / 2 classes = 2
        assert!((val - 2.0).abs() < 1e-10, "expected 2.0, got {val}");
    }

    #[test]
    fn multi_margin_loss_propagates_gradient_through_input() {
        // Regression test for frankentorch-x9cr.
        // multi_margin_loss used to extract values, accumulate the
        // per-sample sum in plain f64, and rebuild a
        // requires_grad=false leaf — silently severing autograd for
        // multi-class margin training paths. After composing through
        // one_hot + relu + pow + sum_dim + mean (all autograd-aware),
        // gradients flow.
        //
        // For input = [[0.0, 3.0]], target = [0], p=1, margin=1:
        //   diff matrix = margin + (input - score_y_b)
        //                = 1 + ([[0, 3]] - [[0, 0]])
        //                = [[1, 4]]
        //   relu(diff)  = [[1, 4]]
        //   masked      = [[1, 4]] * [[0, 1]]    (mask_others)
        //                = [[0, 4]]
        //   powered     = [[0, 4]]   (^1)
        //   per_sample  = (0 + 4) / 2 = 2.0
        //   loss        = mean over batch = 2.0 ✓ (matches existing test)
        //
        // Backward: d loss / d input.
        //   loss = (1/batch) * (1/classes) * sum over batch i, j of
        //          relu(margin - x[i, y_i] + x[i, j])^p * mask_others[i, j]
        // With p=1, the relu sub-gradient is 1 where diff > 0, 0
        // where diff < 0, and 0 at the boundary by FrankenTorch
        // convention.
        //
        // For our example (batch=1, classes=2, target=[0]):
        //   d loss / d x[0, 0] = (1/2) * d/dx[0,0] of sum_j relu(diff[0, j]) * mask_others[0, j]
        //   Only j=1 contributes: diff[0, 1] = margin - x[0,0] + x[0,1] = 1 - 0 + 3 = 4
        //     relu'(4) = 1; ∂diff[0,1]/∂x[0,0] = -1 (subtract score_y)
        //     contribution: 1 * (-1) * 1 = -1
        //   So d loss / d x[0, 0] = -1/2 = -0.5
        //
        //   d loss / d x[0, 1] = (1/2) * d/dx[0,1] of sum_j relu(diff[0, j]) * mask_others[0, j]
        //   j=1 contributes: ∂diff[0,1]/∂x[0,1] = +1
        //     contribution: 1 * 1 * 1 = 1
        //   So d loss / d x[0, 1] = 1/2 = 0.5
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let input = s
            .tensor_variable(vec![0.0, 3.0], vec![1, 2], true)
            .unwrap();
        let target = s.tensor_variable(vec![0.0], vec![1], false).unwrap();
        let loss = s.multi_margin_loss(input, target, 1.0, 1.0).unwrap();
        let report = s.tensor_backward(loss).unwrap();
        let grad = s
            .tensor_gradient(&report, input)
            .expect("multi_margin_loss must propagate gradient through input");
        let expected = [-0.5_f64, 0.5];
        for (i, (&g, &e)) in grad.iter().zip(expected.iter()).enumerate() {
            assert!(
                (g - e).abs() < 1e-12,
                "multi_margin_loss grad[{i}] = {g}, expected {e}"
            );
        }
    }

