        assert!((vals[0] - 0.1).abs() < 1e-10);
        assert!((vals[1] - 0.2).abs() < 1e-10);
        assert!((vals[2] - 0.5).abs() < 1e-10);
        assert!((vals[3] - 0.6).abs() < 1e-10);
