    #[test]
    fn erfinv_tail_values_match_boost_reference() {
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let next_before_one = f64::from_bits(0x3fefffffffffffff);
        let inputs = vec![
            0.999_999_999,
            -0.999_999_999,
            0.999_999_999_999,
            -0.999_999_999_999,
            1.0 - 1e-15,
            -(1.0 - 1e-15),
            next_before_one,
            -next_before_one,
        ];
        let expected = [
            4.320_005_388_105_362,
            -4.320_005_388_105_362,
            5.042_031_898_572_696,
            -5.042_031_898_572_696,
            5.675_915_739_744_712,
            -5.675_915_739_744_712,
            5.863_584_748_755_168,
            -5.863_584_748_755_168,
        ];
        let input = s
            .tensor_variable(inputs.clone(), vec![inputs.len()], false)
            .unwrap();
        let result = s.tensor_erfinv(input).unwrap();
        let vals = s.tensor_values(result).unwrap();

        for ((x, got), want) in inputs.iter().zip(vals.iter()).zip(expected.iter()) {
            assert!(
                (got - want).abs() <= 2e-14,
                "erfinv({x:?}) = {got:?}, want {want:?}"
            );
        }
    }

    #[test]
    fn erfinv_propagates_gradient_via_exp_y_squared() {
        // Regression test for frankentorch-1tax: tensor_erfinv used to
        // extract values, run erfinv_approx, and rebuild a
        // requires_grad=false leaf — silently severing autograd.
        // After wrapping in tensor_apply_function with the analytical
        // backward
        //     d/dx erfinv(x) = sqrt(pi)/2 * exp(erfinv(x)^2)
        // gradients flow through the input.
        //
        // Concretely with y = erfinv(x):
        //   x = 0.0 → y = 0.0 → grad = sqrt(pi)/2 * 1            ≈ 0.8862269
        //   x = 0.5 → y ≈ 0.4769362762 → grad ≈ sqrt(pi)/2 * exp(y^2) ≈ 1.1124302
        //   x =-0.5 → same grad as 0.5 (the derivative is even in y)
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let xs = [0.0, 0.5, -0.5];
        let input = s
            .tensor_variable(xs.to_vec(), vec![xs.len()], true)
            .unwrap();
        let out = s.tensor_erfinv(input).unwrap();
        let y_vals = s.tensor_values(out).unwrap();
        let loss = s.tensor_sum(out).unwrap();
        let report = s.tensor_backward(loss).unwrap();
        let grad = s
            .tensor_gradient(&report, input)
            .expect("erfinv must propagate gradient via exp(y^2) backward");

        let half_sqrt_pi = std::f64::consts::PI.sqrt() * 0.5;
        for (i, &x) in xs.iter().enumerate() {
            let y = y_vals[i];
            let expected = half_sqrt_pi * (y * y).exp();
            // erfinv_approx is Winitzki+Newton; the analytical
            // derivative is exact in y, so the only error is the y
            // approximation feeding exp(y^2). Loose 1e-6 absolute
            // tolerance (matches the precision regime of the forward
            // approximation).
            assert!(
                (grad[i] - expected).abs() < 1e-6,
                "erfinv grad[{i}] at x={x} = {g}, expected sqrt(pi)/2 * exp(y^2) = {expected} (y={y})",
                g = grad[i]
            );
        }
    }

    #[test]
    fn gammaln_known_values() {
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        // lgamma(1) = 0, lgamma(2) = 0, lgamma(0.5) = ln(sqrt(pi))
        let input = s
            .tensor_variable(vec![1.0, 2.0, 0.5], vec![3], false)
            .unwrap();
        let result = s.tensor_gammaln(input).unwrap();
        let vals = s.tensor_values(result).unwrap();
        assert!((vals[0]).abs() < 1e-8, "lgamma(1) = 0, got {}", vals[0]);
        assert!((vals[1]).abs() < 1e-8, "lgamma(2) = 0, got {}", vals[1]);
        let expected_half = 0.5 * std::f64::consts::PI.ln(); // ln(sqrt(pi))
        assert!(
            (vals[2] - expected_half).abs() < 1e-6,
            "lgamma(0.5) = {expected_half}, got {}",
            vals[2]
        );
    }

    #[test]
    fn gammaln_propagates_gradient_via_digamma() {
        // Regression test for frankentorch-1tax: tensor_gammaln used
        // to fail-loud reject tracked inputs because the body just
        // ran libm::lgamma and rebuilt a requires_grad=false leaf.
        // After wrapping in tensor_apply_function with a digamma
        // backward, gradients flow through the input.
        //
        // d/dx lgamma(x) = digamma(x).
        // For input [1.0, 2.0, 3.0, 4.0] under sum loss:
        //   grad[i] = digamma(x_i)
        //   = [-gamma_euler, 1 - gamma_euler, 1.5 - gamma_euler,
        //      11/6 - gamma_euler]
        // Equivalently: digamma(1) = -γ ≈ -0.5772; digamma(n) for
        // integer n: H_{n-1} - γ where H_k is the k-th harmonic number.
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let input = s
            .tensor_variable(vec![1.0, 2.0, 3.0, 4.0], vec![4], true)
            .unwrap();
        let out = s.tensor_gammaln(input).unwrap();
        let loss = s.tensor_sum(out).unwrap();
        let report = s.tensor_backward(loss).unwrap();
        let grad = s
            .tensor_gradient(&report, input)
            .expect("gammaln must propagate gradient via digamma backward");

        let euler = 0.577_215_664_901_532_9_f64;
        let expected = [
            -euler,
            1.0 - euler,
            1.5 - euler,
            (1.0 + 0.5 + 1.0 / 3.0) - euler,
        ];
        for (i, (&g, &e)) in grad.iter().zip(expected.iter()).enumerate() {
            // digamma_approx error envelope (~1e-13 absolute on the
            // smooth interior — matches the bound the scipy
            // conformance test uses for digamma).
            assert!(
                (g - e).abs() < 1e-9,
                "gammaln grad[{i}] at x={} = {g}, expected digamma(x) = {e}",
                [1.0, 2.0, 3.0, 4.0][i]
            );
        }
    }

    #[test]
    fn digamma_known_values() {
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        // psi(1) = -gamma ≈ -0.5772
        let input = s.tensor_variable(vec![1.0], vec![1], false).unwrap();
        let result = s.tensor_digamma(input).unwrap();
        let vals = s.tensor_values(result).unwrap();
        let euler_mascheroni = 0.577_215_664_901_532_9;
        assert!(
            (vals[0] + euler_mascheroni).abs() < 1e-6,
            "psi(1) ≈ -{euler_mascheroni}, got {}",
            vals[0]
        );
    }

    #[test]
    fn digamma_signed_zero_returns_signed_infinity() {
        // ψ(x) ~ -1/x near zero, so the limit is -∞ from the right
        // and +∞ from the left. IEEE 754 distinguishes +0.0 and
        // -0.0; scipy.special.digamma returns -inf and +inf
        // respectively. Previously digamma_approx lumped both into
        // the "NaN at non-positive integer" branch, which silently
        // disagreed with scipy / PyTorch at the most common boundary
        // case.
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let input = s
            .tensor_variable(vec![0.0, -0.0], vec![2], false)
            .unwrap();
        let result = s.tensor_digamma(input).unwrap();
        let vals = s.tensor_values(result).unwrap();
        assert_eq!(vals[0], f64::NEG_INFINITY, "ψ(+0.0) must be -inf");
        assert_eq!(vals[1], f64::INFINITY, "ψ(-0.0) must be +inf");
    }

    #[test]
    fn digamma_propagates_gradient_via_trigamma() {
        // Regression test for frankentorch-1tax: tensor_digamma used
        // to fail-loud reject tracked inputs. After wrapping in
        // tensor_apply_function with a trigamma backward
        // (polygamma(1, x)), gradients flow through the input.
        //
        // d/dx digamma(x) = trigamma(x) = polygamma(1, x).
        // Special integer values:
        //   trigamma(1) = π^2 / 6 ≈ 1.6449340668...
        //   trigamma(2) = π^2 / 6 - 1
        //   trigamma(3) = π^2 / 6 - 1 - 1/4
        //
        // For sum-loss on input [1, 2, 3]: grad = trigamma at each x.
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let input = s
            .tensor_variable(vec![1.0, 2.0, 3.0], vec![3], true)
            .unwrap();
        let out = s.tensor_digamma(input).unwrap();
        let loss = s.tensor_sum(out).unwrap();
        let report = s.tensor_backward(loss).unwrap();
        let grad = s
            .tensor_gradient(&report, input)
            .expect("digamma must propagate gradient via trigamma backward");
        let pi2_6 = std::f64::consts::PI.powi(2) / 6.0;
        let expected = [pi2_6, pi2_6 - 1.0, pi2_6 - 1.0 - 0.25];
        for (i, (&g, &e)) in grad.iter().zip(expected.iter()).enumerate() {
            // polygamma_approx is looser than digamma_approx — a
            // shorter recurrence (shift to x >= 10) and only the
            // leading asymptotic terms — so the empirical envelope
            // is ~5e-6 absolute at small integer x. The harness
            // still catches sign flips, missing factorial terms,
            // and reflection-formula regressions; tightening this
            // bound would require improving polygamma_approx itself.
            assert!(
                (g - e).abs() < 1e-4,
                "digamma grad[{i}] = {g}, expected trigamma({}) = {e}",
                [1.0, 2.0, 3.0][i]
            );
        }
    }

    #[test]
    fn digamma_negative_integer_poles_return_nan() {
        // Poles at -1, -2, -3, ... — the function genuinely has no
        // limit there (the left and right limits differ in sign and
        // diverge), so scipy returns NaN. Verify FrankenTorch does
        // too. The `digamma_signed_zero` test above shows we no
        // longer conflate these with the x==0 case.
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let input = s
            .tensor_variable(vec![-1.0, -2.0, -10.0], vec![3], false)
            .unwrap();
        let result = s.tensor_digamma(input).unwrap();
        let vals = s.tensor_values(result).unwrap();
        for (i, &v) in vals.iter().enumerate() {
            assert!(v.is_nan(), "ψ at negative-integer pole {i} must be NaN, got {v}");
        }
    }

