    #[test]
    fn scatter_add_backward_propagates_to_src() {
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let input = s
            .tensor_variable(vec![0.0, 0.0, 0.0], vec![1, 3], false)
            .unwrap();
        let src = s
            .tensor_variable(vec![1.0, 2.0, 3.0], vec![1, 3], true)
            .unwrap();
        let idx = s
            .tensor_variable(vec![0.0, 1.0, 0.0], vec![1, 3], false)
            .unwrap();
        let result = s.tensor_scatter_add(input, 1, idx, src).unwrap();
        let loss = s.tensor_sum(result).unwrap();
        let report = s.tensor_backward(loss).unwrap();
        let grad = s
            .tensor_gradient(&report, src)
            .expect("scatter_add must propagate gradient to src");
        assert_eq!(grad, &[1.0, 1.0, 1.0]);
    }

    #[test]
    fn scatter_add_backward_propagates_to_input_and_src() {
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let input = s
            .tensor_variable(vec![10.0, 20.0, 30.0], vec![3], true)
            .unwrap();
        let src = s
            .tensor_variable(vec![1.0, 2.0, 3.0], vec![3], true)
            .unwrap();
        let idx = s
            .tensor_variable(vec![0.0, 0.0, 2.0], vec![3], false)
            .unwrap();
        let result = s.tensor_scatter_add(input, 0, idx, src).unwrap();
        let loss = s.tensor_sum(result).unwrap();
        let report = s.tensor_backward(loss).unwrap();
        let input_grad = s
            .tensor_gradient(&report, input)
            .expect("scatter_add must preserve destination gradient");
        let src_grad = s
            .tensor_gradient(&report, src)
            .expect("scatter_add must gather output gradient into src");
        assert_eq!(input_grad, &[1.0, 1.0, 1.0]);
        assert_eq!(src_grad, &[1.0, 1.0, 1.0]);
    }

    #[test]
    fn scatter_backward_propagates_to_src() {
        // Regression test mirroring scatter_add_backward_propagates_to_src:
        // ft-autograd Scatter used to drop the gradient that should
        // flow into `src`, exactly the same severed-autograd pattern
        // ScatterAdd had. Now grad_src is gather(incoming, dim, index)
        // — each src[j] was overwritten into output[index[j]], so a
        // sum-loss gradient at output[index[j]] = 1.0 must show up as
        // src_grad[j] = 1.0 (no double-counting since this test uses
        // unique indices).
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let input = s
            .tensor_variable(vec![10.0, 20.0, 30.0], vec![1, 3], false)
            .unwrap();
        let src = s
            .tensor_variable(vec![1.0, 2.0, 3.0], vec![1, 3], true)
            .unwrap();
        let idx = s
            .tensor_variable(vec![0.0, 1.0, 2.0], vec![1, 3], false)
            .unwrap();
        let result = s.tensor_scatter(input, 1, idx, src).unwrap();
        let loss = s.tensor_sum(result).unwrap();
        let report = s.tensor_backward(loss).unwrap();
        let grad = s
            .tensor_gradient(&report, src)
            .expect("scatter must propagate gradient to src");
        assert_eq!(grad, &[1.0, 1.0, 1.0]);
    }

    #[test]
    fn scatter_backward_propagates_to_input_and_src() {
        // Both prongs at once: input retains gradient at non-overwritten
        // positions; src receives gradient at the overwritten positions.
        // For input=[10,20,30] with indices [0,2] writing to positions
        // 0 and 2, only position 1 of input is preserved unchanged →
        // grad_input = [0, 1, 0]. grad_src = gather(ones, 0, [0,2]) =
        // [1, 1].
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let input = s
            .tensor_variable(vec![10.0, 20.0, 30.0], vec![3], true)
            .unwrap();
        let src = s
            .tensor_variable(vec![100.0, 300.0], vec![2], true)
            .unwrap();
        let idx = s.tensor_variable(vec![0.0, 2.0], vec![2], false).unwrap();
        let result = s.tensor_scatter(input, 0, idx, src).unwrap();
        let loss = s.tensor_sum(result).unwrap();
        let report = s.tensor_backward(loss).unwrap();
        let input_grad = s
            .tensor_gradient(&report, input)
            .expect("scatter must preserve gradient at non-overwritten positions");
        let src_grad = s
            .tensor_gradient(&report, src)
            .expect("scatter must gather output gradient into src");
        assert_eq!(input_grad, &[0.0, 1.0, 0.0]);
        assert_eq!(src_grad, &[1.0, 1.0]);
    }

    #[test]
    fn scatter_backward_honors_last_write_for_duplicate_indices() {
        // Regression: when multiple src positions write to the same
        // output slot via duplicate indices, scatter (non-add) is
        // last-write-wins on CPU (the iteration order in
        // scatter_tensor_contiguous_*). Earlier writes are clobbered
        // and must receive zero gradient. The previous backward
        // gave every src slot the gathered incoming gradient,
        // double-counting the writes that didn't survive.
        //
        // Setup: indices [0, 0, 2] writing src=[10.0, 20.0, 30.0]
        // into a length-3 input. Forward output: position 0 ends up
        // holding 20.0 (the second write), position 2 holds 30.0,
        // position 1 retains its original input value. Sum-loss
        // incoming gradient is ones throughout.
        //
        // Expected backward:
        //   grad_input = [0, 1, 0]    (positions 0 and 2 overwritten)
        //   grad_src   = [0, 1, 1]    (src[0] is the *first* write to
        //                              output 0 and was clobbered →
        //                              zero; src[1] is the last write
        //                              to output 0 → 1; src[2] is the
        //                              only write to output 2 → 1)
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let input = s
            .tensor_variable(vec![1.0, 2.0, 3.0], vec![3], true)
            .unwrap();
        let src = s
            .tensor_variable(vec![10.0, 20.0, 30.0], vec![3], true)
            .unwrap();
        let idx = s
            .tensor_variable(vec![0.0, 0.0, 2.0], vec![3], false)
            .unwrap();
        let result = s.tensor_scatter(input, 0, idx, src).unwrap();
        // Forward parity: last write (20.0) wins at index 0.
        assert_eq!(s.tensor_values(result).unwrap(), vec![20.0, 2.0, 30.0]);

        let loss = s.tensor_sum(result).unwrap();
        let report = s.tensor_backward(loss).unwrap();
        let input_grad = s
            .tensor_gradient(&report, input)
            .expect("scatter must preserve gradient at non-overwritten positions");
        let src_grad = s
            .tensor_gradient(&report, src)
            .expect("scatter must gather output gradient into the last-writing src slots");
        assert_eq!(input_grad, &[0.0, 1.0, 0.0]);
        assert_eq!(
            src_grad,
            &[0.0, 1.0, 1.0],
            "src[0] was overwritten by src[1]; only the last write contributes"
        );
    }

    #[test]
    fn scatter_backward_long_duplicate_chain_picks_last_writer() {
        // Stress the last-write tracking with three writes to the
        // same target. indices [1, 1, 1] all write to position 1
        // sequentially; only src[2] (the third write) survives.
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let input = s
            .tensor_variable(vec![1.0, 2.0, 3.0], vec![3], false)
            .unwrap();
        let src = s
            .tensor_variable(vec![10.0, 20.0, 30.0], vec![3], true)
            .unwrap();
        let idx = s
            .tensor_variable(vec![1.0, 1.0, 1.0], vec![3], false)
            .unwrap();
        let result = s.tensor_scatter(input, 0, idx, src).unwrap();
        // Forward parity: last write (30.0) wins.
        assert_eq!(s.tensor_values(result).unwrap(), vec![1.0, 30.0, 3.0]);

        let loss = s.tensor_sum(result).unwrap();
        let report = s.tensor_backward(loss).unwrap();
        let src_grad = s
            .tensor_gradient(&report, src)
            .expect("scatter must mask out non-last writers in src");
        assert_eq!(
            src_grad,
            &[0.0, 0.0, 1.0],
            "only the third write survives; first two were overwritten"
        );
    }

    #[test]
    fn scatter_add_as_inverse_of_gather() {
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        // Gather: select elements then scatter_add back should recover sums
        let src_data = vec![10.0, 20.0, 30.0, 40.0, 50.0];
        let src = s.tensor_variable(src_data.clone(), vec![5], false).unwrap();
        let idx = s
            .tensor_variable(vec![1.0, 3.0, 4.0], vec![3], false)
            .unwrap();
        let gathered = s.tensor_gather(src, 0, idx).unwrap();
        let gathered_vals = s.tensor_values(gathered).unwrap();
        assert!((gathered_vals[0] - 20.0).abs() < 1e-10);
        assert!((gathered_vals[1] - 40.0).abs() < 1e-10);
        assert!((gathered_vals[2] - 50.0).abs() < 1e-10);

        // Scatter_add gathered values back
        let zeros = s.tensor_variable(vec![0.0; 5], vec![5], false).unwrap();
        let idx2 = s
            .tensor_variable(vec![1.0, 3.0, 4.0], vec![3], false)
            .unwrap();
        let result = s.tensor_scatter_add(zeros, 0, idx2, gathered).unwrap();
        let vals = s.tensor_values(result).unwrap();
        assert!((vals[1] - 20.0).abs() < 1e-10);
        assert!((vals[3] - 40.0).abs() < 1e-10);
        assert!((vals[4] - 50.0).abs() < 1e-10);
    }

    #[test]
    fn scatter_add_2d_dim0() {
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        // 3x2 input, scatter along dim 0
        let input = s.tensor_variable(vec![0.0; 6], vec![3, 2], false).unwrap();
        let src = s
            .tensor_variable(vec![1.0, 2.0, 3.0, 4.0], vec![2, 2], false)
            .unwrap();
        // row 0 of src -> row 2 of output, row 1 of src -> row 0
        let idx = s
            .tensor_variable(vec![2.0, 2.0, 0.0, 0.0], vec![2, 2], false)
            .unwrap();
        let result = s.tensor_scatter_add(input, 0, idx, src).unwrap();
        let vals = s.tensor_values(result).unwrap();
        // row 0: [0+3, 0+4] = [3, 4]
        assert!((vals[0] - 3.0).abs() < 1e-10);
        assert!((vals[1] - 4.0).abs() < 1e-10);
        // row 2: [0+1, 0+2] = [1, 2]
        assert!((vals[4] - 1.0).abs() < 1e-10);
        assert!((vals[5] - 2.0).abs() < 1e-10);
    }

