        let result = s
            .tensor_index_put(input, &[row_idx, col_idx], values, false)
            .unwrap();
        let vals = s.tensor_values(result).unwrap();
        // (0,2)=10, (1,1)=20, (2,0)=30
        assert!((vals[2] - 10.0).abs() < 1e-10);
        assert!((vals[4] - 20.0).abs() < 1e-10);
        assert!((vals[6] - 30.0).abs() < 1e-10);
